    dryRun,
    isDraftTemplatesLoading,
    limitError,
    limitInput,
    draftTemplates,
    profiles,
    selectedDraftTemplateId,
    selectedProfileId,
    onDryRunChange,
    onDraftTemplateSelect,
    onLimitInputChange,
