  normalizeShippingGroupRuleCategoryIds,
} from '@/shared/lib/products/utils/shipping-group-rule-conflicts';
import { Alert } from '@/shared/ui/alert';
import { Badge } from '@/shared/ui/badge';
import { Button } from '@/shared/ui/button';
import { EmptyState } from '@/shared/ui/empty-state';
import { FormField, FormSection } from '@/shared/ui/form-section';
import { FormModal } from '@/shared/ui/FormModal';
import { Input } from '@/shared/ui/input';
import { MultiSelect } from '@/shared/ui/multi-select';
import { SelectSimple } from '@/shared/ui/select-simple';
import { ConfirmModal } from '@/shared/ui/templates/modals/ConfirmModal';
import { SimpleSettingsList } from '@/shared/ui/templates/SimpleSettingsList';
import { Textarea } from '@/shared/ui/textarea';
import { useToast } from '@/shared/ui/toast';

import { logClientCatch } from '@/shared/utils/observability/client-error-logger';

import { useProductSettingsShippingGroupsContext } from './ProductSettingsContext';
import {
  DRAFT_SHIPPING_GROUP_ID,
  readConflictMetaFromApiError,
  formatShippingGroupConflictMessage,
  isShippingGroupNotFoundError,
  summarizeRuleDescendantCoverage,
} from '../../utils/shipping-group-settings-utils';

const toTrimmedString = (value: unknown): string =>
  typeof value === 'string' ? value.trim() : '';

export function ShippingGroupsSettings(): React.JSX.Element {
  const {
    loadingShippingGroups: loading,
    shippingGroups,
    catalogs,
    selectedShippingGroupCatalogId: selectedCatalogId,
    onShippingGroupCatalogChange: onCatalogChange,
    onRefreshShippingGroups: onRefresh,
  } = useProductSettingsShippingGroupsContext();

  const { toast } = useToast();
  const [showModal, setShowModal] = useState(false);
  const [editingShippingGroup, setEditingShippingGroup] = useState<ProductShippingGroup | null>(null);
  const [shippingGroupToDelete, setShippingGroupToDelete] =
    useState<ProductShippingGroup | null>(null);
  const [formData, setFormData] = useState<ShippingGroupFormData>({
    name: '',
    description: '',
    catalogId: '',
    traderaShippingCondition: '',
    traderaShippingPriceEur: '',
    autoAssignCategoryIds: [],
    autoAssignCurrencyCodes: [],
  });

  const {
    data: selectedCatalogCategories = [],
    isLoading: loadingSelectedCatalogCategories,
  } = useProductMetadataCategories(selectedCatalogId ?? undefined, {
    enabled: Boolean(selectedCatalogId),
  });
  const {
    data: modalCatalogCategories = [],
    isLoading: loadingModalCatalogCategories,
  } = useProductMetadataCategories(formData.catalogId || undefined, {
    enabled: Boolean(formData.catalogId),
  });
  const {
    data: modalCatalogShippingGroups = [],
    isLoading: loadingModalCatalogShippingGroups,
  } = useProductMetadataShippingGroups(formData.catalogId || undefined, {
    enabled: Boolean(formData.catalogId) && showModal,
  });

  const saveShippingGroupMutation = useSaveShippingGroupMutation();
  const deleteShippingGroupMutation = useDeleteShippingGroupMutation();
  const normalizedModalRuleIds = useMemo(
    () =>
      normalizeShippingGroupRuleCategoryIds({
        categoryIds: formData.autoAssignCategoryIds,
        categories: modalCatalogCategories,
      }),
    [formData.autoAssignCategoryIds, modalCatalogCategories]
  );
  const redundantModalRuleIds = useMemo(
    () =>
      findRedundantShippingGroupRuleCategoryIds({
        categoryIds: formData.autoAssignCategoryIds,
        categories: modalCatalogCategories,
      }),
    [formData.autoAssignCategoryIds, modalCatalogCategories]
  );

  const openCreateModal = (): void => {
    if (!selectedCatalogId) {
      toast('Please select a catalog first.', { variant: 'error' });
      return;
    }
    setEditingShippingGroup(null);
    setFormData({
      name: '',
      description: '',
      catalogId: selectedCatalogId,
      traderaShippingCondition: '',
      traderaShippingPriceEur: '',
      autoAssignCategoryIds: [],
      autoAssignCurrencyCodes: [],
    });
    setShowModal(true);
  };

  const openEditModal = (shippingGroup: ProductShippingGroup): void => {
    setEditingShippingGroup(shippingGroup);
    const nextFormData: ShippingGroupFormData = {
      name: shippingGroup.name,
      description: shippingGroup.description ?? '',
      catalogId: shippingGroup.catalogId,
      traderaShippingCondition: shippingGroup.traderaShippingCondition ?? '',
      traderaShippingPriceEur:
        typeof shippingGroup.traderaShippingPriceEur === 'number' &&
        Number.isFinite(shippingGroup.traderaShippingPriceEur)
          ? String(shippingGroup.traderaShippingPriceEur)
          : '',
      autoAssignCategoryIds: Array.isArray(shippingGroup.autoAssignCategoryIds)
        ? shippingGroup.autoAssignCategoryIds
        : [],
      autoAssignCurrencyCodes: Array.isArray(shippingGroup.autoAssignCurrencyCodes)
        ? shippingGroup.autoAssignCurrencyCodes
        : [],
    };
    setFormData(nextFormData);
    setShowModal(true);
  };

  const handleSave = async (): Promise<void> => {
    if (!formData.name.trim()) {
      toast('Shipping group name is required.', { variant: 'error' });
      return;
    }
    if (!formData.catalogId) {
      toast('Catalog is required.', { variant: 'error' });
      return;
    }
    const trimmedShippingPrice = formData.traderaShippingPriceEur.trim();
    if (trimmedShippingPrice) {
      const parsedShippingPrice = Number(trimmedShippingPrice);
      if (!Number.isFinite(parsedShippingPrice) || parsedShippingPrice < 0) {
        toast('Tradera shipping price must be a non-negative EUR amount.', {
          variant: 'error',
        });
        return;
      }
    }
    if (modalShippingGroupRuleConflicts.length > 0) {
      toast(
        formatShippingGroupConflictMessage({
          conflicts: modalShippingGroupRuleConflicts,
          categoryLabelById: modalCategoryLabelById,
          draftShippingGroupId: editingShippingGroup?.id ?? DRAFT_SHIPPING_GROUP_ID,
        }),
        { variant: 'error' }
      );
      return;
    }

    try {
      await saveShippingGroupMutation.mutateAsync({
        id: editingShippingGroup?.id,
        data: {
          name: formData.name.trim(),
          description: formData.description.trim() || null,
          catalogId: formData.catalogId,
          traderaShippingCondition: formData.traderaShippingCondition.trim() || null,
          traderaShippingPriceEur: trimmedShippingPrice ? Number(trimmedShippingPrice) : null,
          autoAssignCategoryIds: normalizedModalRuleIds,
          autoAssignCurrencyCodes: formData.autoAssignCurrencyCodes,
        },
      });

      toast(editingShippingGroup ? 'Shipping group updated.' : 'Shipping group created.', {
        variant: 'success',
      });
      setShowModal(false);
      onRefresh();
    } catch (error) {
      logClientCatch(error, {
        source: 'ShippingGroupsSettings',
        action: 'saveShippingGroup',
        shippingGroupId: editingShippingGroup?.id,
      });
      const conflictMeta = readConflictMetaFromApiError(error);
      const message =
        conflictMeta.length > 0
          ? formatShippingGroupConflictMessage({
              conflicts: conflictMeta,
              categoryLabelById: modalCategoryLabelById,
              draftShippingGroupId: editingShippingGroup?.id ?? DRAFT_SHIPPING_GROUP_ID,
            })
          : error instanceof Error
            ? error.message
            : 'Failed to save shipping group.';
      toast(message, { variant: 'error' });
    }
  };

  const handleDelete = useCallback((shippingGroup: ProductShippingGroup): void => {
    setShippingGroupToDelete(shippingGroup);
  }, []);

  const handleConfirmDelete = async (): Promise<void> => {
    if (!shippingGroupToDelete) return;

    try {
      await deleteShippingGroupMutation.mutateAsync({
        id: shippingGroupToDelete.id,
        catalogId: selectedCatalogId,
      });
      toast('Shipping group deleted.', { variant: 'success' });
      onRefresh();
    } catch (error) {
      logClientCatch(error, {
        source: 'ShippingGroupsSettings',
        action: 'deleteShippingGroup',
        shippingGroupId: shippingGroupToDelete.id,
      });
      if (isShippingGroupNotFoundError(error)) {
        toast('Shipping group was already removed.', { variant: 'success' });
        onRefresh();
        return;
      }
      const message = error instanceof Error ? error.message : 'Failed to delete shipping group.';
      toast(message, { variant: 'error' });
    } finally {
      setShippingGroupToDelete(null);
    }
  };

  const selectedCatalog = catalogs.find((catalog: Catalog) => catalog.id === selectedCatalogId);
  const catalogOptions = useMemo<Array<LabeledOptionDto<string>>>(
    () =>
      catalogs.map((catalog: Catalog) => ({
        value: catalog.id,
        label: `${catalog.name}${catalog.isDefault ? ' (Default)' : ''}`,
      })),
    [catalogs]
  );
  const selectedCategoryLabelById = useMemo(
    () => buildCategoryPathLabelMap(selectedCatalogCategories),
    [selectedCatalogCategories]
  );
  const modalCategoryLabelById = useMemo(
    () => buildCategoryPathLabelMap(modalCatalogCategories),
    [modalCatalogCategories]
  );
  const redundantModalRuleSummary = useMemo(
    () =>
      formatCategoryRuleSummary({
        categoryIds: redundantModalRuleIds,
        categoryLabelById: modalCategoryLabelById,
      }),
    [modalCategoryLabelById, redundantModalRuleIds]
  );
  const normalizedModalRuleSummary = useMemo(
    () =>
      formatCategoryRuleSummary({
        categoryIds: normalizedModalRuleIds,
        categoryLabelById: modalCategoryLabelById,
      }),
    [modalCategoryLabelById, normalizedModalRuleIds]
  );
  const missingModalRuleSummary = useMemo(() => {
    const missingRuleIds = formData.autoAssignCategoryIds
      .map((categoryId) => toTrimmedString(categoryId))
      .filter((categoryId) => categoryId.length > 0 && !modalCategoryLabelById.has(categoryId));

    return missingRuleIds.length > 0 ? missingRuleIds.join(', ') : null;
  }, [formData.autoAssignCategoryIds, modalCategoryLabelById]);
  const shouldShowNormalizedModalRuleSummary = useMemo(() => {
    const rawRuleIds = formData.autoAssignCategoryIds
      .map((categoryId) => toTrimmedString(categoryId))
      .filter(Boolean);

    if (rawRuleIds.length !== normalizedModalRuleIds.length) {
      return true;
    }

    return rawRuleIds.some((categoryId, index) => categoryId !== normalizedModalRuleIds[index]);
  }, [formData.autoAssignCategoryIds, normalizedModalRuleIds]);
  const shippingGroupRuleConflicts = useMemo(
    () =>
      buildShippingGroupRuleConflicts({
        shippingGroups,
        categories: selectedCatalogCategories,
      }),
    [selectedCatalogCategories, shippingGroups]
  );
  const modalCategoryOptions = useMemo<Array<LabeledOptionDto<string>>>(
    () =>
      modalCatalogCategories.map((category) => ({
        value: category.id,
        label: modalCategoryLabelById.get(category.id) ?? category.name,
      })),
    [modalCatalogCategories, modalCategoryLabelById]
  );
  const shippingGroupRuleCoverageById = useMemo(() => {
    const coverageById = new Map<
      string,
      {
        descendantIds: string[];
        descendantSummary: string | null;
      }
    >();

    for (const shippingGroup of shippingGroups) {
      const normalizedRuleIds = normalizeShippingGroupRuleCategoryIds({
        categoryIds: Array.isArray(shippingGroup.autoAssignCategoryIds)
          ? shippingGroup.autoAssignCategoryIds
          : [],
        categories: selectedCatalogCategories,
      });

      coverageById.set(
        shippingGroup.id,
        summarizeRuleDescendantCoverage({
          categoryIds: normalizedRuleIds,
          categories: selectedCatalogCategories,
          categoryLabelById: selectedCategoryLabelById,
        })
      );
    }

    return coverageById;
  }, [selectedCatalogCategories, selectedCategoryLabelById, shippingGroups]);
  const shippingGroupNormalizedRuleSummaryById = useMemo(() => {
    const summaryById = new Map<string, string | null>();

    for (const shippingGroup of shippingGroups) {
      const normalizedRuleIds = normalizeShippingGroupRuleCategoryIds({
        categoryIds: Array.isArray(shippingGroup.autoAssignCategoryIds)
          ? shippingGroup.autoAssignCategoryIds
          : [],
        categories: selectedCatalogCategories,
      });

      summaryById.set(
        shippingGroup.id,
        formatCategoryRuleSummary({
          categoryIds: normalizedRuleIds,
          categoryLabelById: selectedCategoryLabelById,
        })
      );
    }

    return summaryById;
  }, [selectedCatalogCategories, selectedCategoryLabelById, shippingGroups]);
  const shippingGroupRedundantRuleSummaryById = useMemo(() => {
    const summaryById = new Map<string, string | null>();

    for (const shippingGroup of shippingGroups) {
      const redundantRuleIds = findRedundantShippingGroupRuleCategoryIds({
        categoryIds: Array.isArray(shippingGroup.autoAssignCategoryIds)
          ? shippingGroup.autoAssignCategoryIds
          : [],
        categories: selectedCatalogCategories,
      });

      summaryById.set(
        shippingGroup.id,
        formatCategoryRuleSummary({
          categoryIds: redundantRuleIds,
          categoryLabelById: selectedCategoryLabelById,
        })
      );
    }

    return summaryById;
  }, [selectedCatalogCategories, selectedCategoryLabelById, shippingGroups]);
  const shippingGroupMissingRuleSummaryById = useMemo(() => {
    const summaryById = new Map<string, string | null>();

    for (const shippingGroup of shippingGroups) {
      const missingRuleIds = (Array.isArray(shippingGroup.autoAssignCategoryIds)
        ? shippingGroup.autoAssignCategoryIds
        : []
      )
        .map((categoryId) => toTrimmedString(categoryId))
        .filter((categoryId) => categoryId.length > 0 && !selectedCategoryLabelById.has(categoryId));

      summaryById.set(
        shippingGroup.id,
        missingRuleIds.length > 0 ? missingRuleIds.join(', ') : null
      );
    }

    return summaryById;
  }, [selectedCategoryLabelById, shippingGroups]);
  const shippingGroupsWithRedundantRules = useMemo(
    () =>
      shippingGroups.filter((shippingGroup) =>
        Boolean(shippingGroupRedundantRuleSummaryById.get(shippingGroup.id))
      ),
    [shippingGroupRedundantRuleSummaryById, shippingGroups]
  );
  const shippingGroupsWithMissingRuleCategories = useMemo(
    () =>
      shippingGroups.filter((shippingGroup) =>
        Boolean(shippingGroupMissingRuleSummaryById.get(shippingGroup.id))
      ),
    [shippingGroupMissingRuleSummaryById, shippingGroups]
  );
  const modalShippingGroupRuleConflicts = useMemo(() => {
    const draftRuleIds = normalizedModalRuleIds;
    if (!formData.catalogId || draftRuleIds.length === 0) {
      return [];
    }

    const draftShippingGroup: ProductShippingGroup = {
      id: editingShippingGroup?.id ?? DRAFT_SHIPPING_GROUP_ID,
      name: formData.name.trim() || 'This shipping group',
      description: formData.description.trim() || null,
      catalogId: formData.catalogId,
      traderaShippingCondition: formData.traderaShippingCondition.trim() || null,
      traderaShippingPriceEur: formData.traderaShippingPriceEur.trim()
        ? Number(formData.traderaShippingPriceEur)
        : null,
      autoAssignCategoryIds: draftRuleIds,
      autoAssignCurrencyCodes: [],
    };
    const modalPeerShippingGroups = modalCatalogShippingGroups.filter(
      (shippingGroup) => shippingGroup.id !== draftShippingGroup.id
    );

    return buildShippingGroupRuleConflicts({
      shippingGroups: [draftShippingGroup, ...modalPeerShippingGroups],
      categories: modalCatalogCategories,
    }).filter((conflict) => conflict.groupIds.includes(draftShippingGroup.id));
  }, [
    editingShippingGroup?.id,
    formData.catalogId,
    formData.description,
    formData.name,
    formData.traderaShippingCondition,
    formData.traderaShippingPriceEur,
    modalCatalogCategories,
    modalCatalogShippingGroups,
    normalizedModalRuleIds,
  ]);
  const modalRuleCoverage = useMemo(
    () =>
      summarizeRuleDescendantCoverage({
        categoryIds: normalizedModalRuleIds,
        categories: modalCatalogCategories,
        categoryLabelById: modalCategoryLabelById,
      }),
    [modalCatalogCategories, modalCategoryLabelById, normalizedModalRuleIds]
  );

  return (
    <div className='space-y-5'>
      <FormSection
        title='Select Catalog'
        description='Shipping groups are managed per catalog.'
        className='p-4'
      >
        <div className='w-full max-w-xs mt-4'>
          <SelectSimple
            size='sm'
            value={selectedCatalogId || ''}
            onValueChange={onCatalogChange}
            options={catalogOptions}
            placeholder='Select a catalog...'
            ariaLabel='Catalog'
            title='Select a catalog...'
          />
        </div>
      </FormSection>

      {selectedCatalogId && (
        <>
          <div className='flex justify-start'>
            <Button onClick={openCreateModal} className='bg-white text-gray-900 hover:bg-gray-200'>
              <Plus className='size-4 mr-2' />
              Add Shipping Group
            </Button>
          </div>

          <FormSection
            title={`Shipping Groups for "${selectedCatalog?.name}"`}
            description='Assign these internal shipping groups to products, then map them into Tradera listing behavior.'
            className='p-4'
          >
            {shippingGroupRuleConflicts.length > 0 ? (
              <Alert variant='warning' className='mb-4'>
                <div className='space-y-1 text-sm'>
                  <p>
                    Conflicting auto-assign rules detected. Products in overlapping categories will
                    need a manual shipping-group override unless you adjust these rules.
                  </p>
                  {shippingGroupRuleConflicts.map((conflict) => {
                    const overlapLabel =
                      formatCategoryRuleSummary({
                        categoryIds: conflict.overlapCategoryIds,
                        categoryLabelById: selectedCategoryLabelById,
                      }) ?? `${conflict.overlapCategoryIds.length} categories`;

                    return (
                      <p key={conflict.groupIds.join(':')}>
                        <strong>{conflict.groupNames[0]}</strong> and{' '}
                        <strong>{conflict.groupNames[1]}</strong> both match{' '}
                        <strong>{overlapLabel}</strong>.
                      </p>
                    );
                  })}
                </div>
              </Alert>
            ) : null}

            {shippingGroupsWithRedundantRules.length > 0 ? (
              <Alert variant='warning' className='mb-4'>
                <div className='space-y-1 text-sm'>
                  <p>
                    Some auto-assign rules include descendant categories already covered by parent
                    categories. Edit and save these groups to simplify them.
                  </p>
                  {shippingGroupsWithRedundantRules.map((shippingGroup) => (
                    <p key={shippingGroup.id}>
                      <strong>{shippingGroup.name}</strong> redundantly includes{' '}
                      <strong>{shippingGroupRedundantRuleSummaryById.get(shippingGroup.id)}</strong>.
                    </p>
                  ))}
                </div>
              </Alert>
            ) : null}

            {shippingGroupsWithMissingRuleCategories.length > 0 ? (
              <Alert variant='warning' className='mb-4'>
                <div className='space-y-1 text-sm'>
                  <p>
                    Some auto-assign rules reference categories that no longer exist in this
                    catalog. Edit and save these groups to repair or remove those rule entries.
                  </p>
                  {shippingGroupsWithMissingRuleCategories.map((shippingGroup) => (
                    <p key={shippingGroup.id}>
                      <strong>{shippingGroup.name}</strong> references missing categories:{' '}
                      <strong>{shippingGroupMissingRuleSummaryById.get(shippingGroup.id)}</strong>.
                    </p>
                  ))}
                </div>
              </Alert>
            ) : null}

            <div className='mt-4'>
              <SimpleSettingsList
                items={shippingGroups.map((shippingGroup: ProductShippingGroup) => ({
                  id: shippingGroup.id,
                  title: shippingGroup.name,
                  description: shippingGroup.description ?? undefined,
                  subtitle:
                    [
                      Array.isArray(shippingGroup.autoAssignCategoryIds) &&
                      shippingGroup.autoAssignCategoryIds.length > 0
                        ? `Categories (${shippingGroup.autoAssignCategoryIds.length}): ${
                            shippingGroupNormalizedRuleSummaryById.get(shippingGroup.id) ??
                            `${shippingGroup.autoAssignCategoryIds.length} categories`
                          }`
                        : null,
                      Array.isArray(shippingGroup.autoAssignCategoryIds) &&
                      shippingGroup.autoAssignCategoryIds.length > 0
                        ? `Auto: ${
                            shippingGroupNormalizedRuleSummaryById.get(shippingGroup.id) ??
                            `${shippingGroup.autoAssignCategoryIds.length} categories`
                          }${
                            (shippingGroupRuleCoverageById.get(shippingGroup.id)?.descendantIds
                              .length ?? 0) > 0
                              ? ' (+ descendants)'
                              : ''
                          }`
                        : null,
                      shippingGroup.traderaShippingCondition ||
                      typeof shippingGroup.traderaShippingPriceEur === 'number'
                        ? `Tradera: ${
                            shippingGroup.traderaShippingCondition || 'Shipping modal'
                          }${
                            typeof shippingGroup.traderaShippingPriceEur === 'number'
                              ? ` · EUR ${shippingGroup.traderaShippingPriceEur.toFixed(2)}`
                              : ''
                          }`
                        : null,
                      shippingGroupRedundantRuleSummaryById.get(shippingGroup.id)
                        ? `Redundant: ${shippingGroupRedundantRuleSummaryById.get(shippingGroup.id)}`
                        : null,
                      shippingGroupMissingRuleSummaryById.get(shippingGroup.id)
                        ? `Missing: ${shippingGroupMissingRuleSummaryById.get(shippingGroup.id)}`
                        : null,
                    ]
                      .filter((value): value is string => Boolean(value))
                      .join(' · ') || undefined,
                  original: shippingGroup,
                }))}
                isLoading={loading || loadingSelectedCatalogCategories}
                onEdit={(item) => openEditModal(item.original)}
                onDelete={(item) => handleDelete(item.original)}
                emptyMessage='No shipping groups yet. Create shipping groups and assign them to products before mapping delivery behavior.'
              />
            </div>
          </FormSection>
        </>
      )}

      {!selectedCatalogId && catalogs.length === 0 && (
        <EmptyState
          title='No catalogs found'
          description='Please create a catalog first in the Catalogs section before adding shipping groups.'
        />
      )}

      <ConfirmModal
        isOpen={Boolean(shippingGroupToDelete)}
        onClose={() => setShippingGroupToDelete(null)}
        onConfirm={handleConfirmDelete}
        title='Delete Shipping Group'
        message={`Are you sure you want to delete shipping group "${shippingGroupToDelete?.name}"? This action cannot be undone.`}
        confirmText='Delete'
        isDangerous={true}
      />

      {showModal && (
        <FormModal
          open={showModal}
          onClose={(): void => setShowModal(false)}
          title={editingShippingGroup ? 'Edit Shipping Group' : 'Create Shipping Group'}
          onSave={(): void => {
            void handleSave();
          }}
          isSaving={saveShippingGroupMutation.isPending}
          size='md'
        >
          <div className='space-y-4'>
            <FormField label='Name'>
              <Input
                className='h-9'
                value={formData.name}
                onChange={(event: React.ChangeEvent<HTMLInputElement>): void =>
                  setFormData((prev: ShippingGroupFormData) => ({
                    ...prev,
                    name: event.target.value,
                  }))
                }
                placeholder='Shipping group name'
                aria-label='Shipping group name'
                title='Shipping group name'
              />
            </FormField>

            <FormField label='Catalog'>
              <SelectSimple
                size='sm'
                value={formData.catalogId}
                onValueChange={(value: string): void =>
                  setFormData((prev: ShippingGroupFormData) => ({
                    ...prev,
                    catalogId: value,
                    autoAssignCategoryIds: [],
                  }))
                }
                options={catalogOptions}
                placeholder='Select catalog'
                ariaLabel='Select catalog'
                title='Select catalog'
              />
            </FormField>

            <FormField
              label='Description'
              description='Optional internal note about when this shipping group should be used.'
            >
              <Textarea
                value={formData.description}
                onChange={(event: React.ChangeEvent<HTMLTextAreaElement>): void =>
                  setFormData((prev: ShippingGroupFormData) => ({
                    ...prev,
                    description: event.target.value,
                  }))
                }
                placeholder='Internal shipping notes'
                aria-label='Shipping group description'
                title='Shipping group description'
              />
            </FormField>

            <FormField
              label='Auto-assign from Categories'
              description='Optional rule: products in these categories or their descendants use this shipping group automatically unless the product has a manual shipping group.'
            >
              <div className='space-y-3'>
                <MultiSelect
                  options={modalCategoryOptions}
                  selected={formData.autoAssignCategoryIds}
                  onChange={(values: string[]): void =>
                    setFormData((prev: ShippingGroupFormData) => ({
                      ...prev,
                      autoAssignCategoryIds: normalizeShippingGroupRuleCategoryIds({
                        categoryIds: values,
                        categories: modalCatalogCategories,
                      }),
                    }))
                  }
                  placeholder='Select categories for automatic assignment'
                  searchPlaceholder='Search categories...'
                  disabled={!formData.catalogId}
                  loading={loadingModalCatalogCategories}
                  emptyMessage='No categories available for this catalog.'
                />

                {formData.catalogId && !loadingModalCatalogCategories ? (
                  <p className='text-xs text-muted-foreground'>
                    {modalCategoryOptions.length === 0
                      ? 'No categories are available in this catalog yet.'
                      : modalCategoryOptions.length === 1
                        ? '1 category is available in this catalog. You can still attach multiple categories once more categories exist.'
                        : `${modalCategoryOptions.length} categories are available in this catalog. You can attach more than one category to the same shipping group.`}
                  </p>
                ) : null}

                {formData.autoAssignCategoryIds.length > 0 ? (
                  <div className='space-y-2'>
                    <p className='text-xs font-medium text-foreground'>
                      Selected categories ({formData.autoAssignCategoryIds.length})
                    </p>
                    <div className='flex flex-wrap gap-2'>
                      {formData.autoAssignCategoryIds.map((categoryId) => {
                        const categoryLabel = modalCategoryLabelById.get(categoryId) ?? categoryId;

                        return (
                          <Badge
                            key={categoryId}
                            variant='outline'
                            onRemove={(): void =>
                              setFormData((prev: ShippingGroupFormData) => ({
                                ...prev,
                                autoAssignCategoryIds: prev.autoAssignCategoryIds.filter(
                                  (selectedCategoryId) => selectedCategoryId !== categoryId
                                ),
                              }))
                            }
                            removeLabel={`Remove ${categoryLabel}`}
                          >
                            {categoryLabel}
                          </Badge>
                        );
                      })}
                    </div>
                  </div>
                ) : null}
              </div>
            </FormField>

            {modalRuleCoverage.descendantSummary ? (
              <Alert variant='info' className='-mt-2'>
                <div className='text-sm'>
                  This rule also matches descendant categories:{' '}
                  <strong>{modalRuleCoverage.descendantSummary}</strong>.
                </div>
              </Alert>
            ) : null}

            {redundantModalRuleSummary ? (
              <Alert variant='info' className='-mt-2'>
                <div className='text-sm'>
                  Redundant descendant categories will be omitted on save:{' '}
                  <strong>{redundantModalRuleSummary}</strong>.
                </div>
              </Alert>
            ) : null}

            {missingModalRuleSummary ? (
              <Alert variant='warning' className='-mt-2'>
                <div className='text-sm'>
                  Missing categories will be removed on save:{' '}
                  <strong>{missingModalRuleSummary}</strong>.
                </div>
              </Alert>
            ) : null}

            {shouldShowNormalizedModalRuleSummary ? (
              <Alert variant='info' className='-mt-2'>
                <div className='text-sm'>
                  Effective auto-assign rule after save:{' '}
                  <strong>{normalizedModalRuleSummary ?? 'None'}</strong>.
                </div>
              </Alert>
            ) : null}

            {!loadingModalCatalogShippingGroups && modalShippingGroupRuleConflicts.length > 0 ? (
              <Alert variant='warning' className='-mt-2'>
                <div className='space-y-1 text-sm'>
                  <p>
                    This auto-assign rule overlaps with other shipping groups in this catalog.
                    Products in the overlapping categories will need a manual shipping-group
                    override unless you adjust these rules.
                  </p>
                  {modalShippingGroupRuleConflicts.map((conflict) => {
                    const overlapLabel =
                      formatCategoryRuleSummary({
                        categoryIds: conflict.overlapCategoryIds,
                        categoryLabelById: modalCategoryLabelById,
                      }) ?? `${conflict.overlapCategoryIds.length} categories`;
                    const otherGroupName =
                      conflict.groupIds[0] === (editingShippingGroup?.id ?? DRAFT_SHIPPING_GROUP_ID)
                        ? conflict.groupNames[1]
                        : conflict.groupNames[0];

                    return (
                      <p key={conflict.groupIds.join(':')}>
                        Overlaps with <strong>{otherGroupName}</strong> on{' '}
                        <strong>{overlapLabel}</strong>.
                      </p>
                    );
                  })}
                </div>
              </Alert>
            ) : null}

            <FormField
              label='Tradera Shipping Condition'
              description='Optional Tradera-facing shipping/delivery label to use later in listing flows.'
            >
              <Input
                className='h-9'
                value={formData.traderaShippingCondition}
                onChange={(event: React.ChangeEvent<HTMLInputElement>): void =>
                  setFormData((prev: ShippingGroupFormData) => ({
                    ...prev,
                    traderaShippingCondition: event.target.value,
                  }))
                }
                placeholder='Buyer pays shipping'
                aria-label='Tradera shipping condition'
                title='Tradera shipping condition'
              />
            </FormField>

            <FormField
              label='Tradera Shipping Price (EUR)'
              description='Optional EUR amount to use when Tradera opens the shipping options modal during browser listings.'
            >
              <Input
                className='h-9'
                type='number'
                min='0'
                step='0.01'
                value={formData.traderaShippingPriceEur}
                onChange={(event: React.ChangeEvent<HTMLInputElement>): void =>
                  setFormData((prev: ShippingGroupFormData) => ({
                    ...prev,
                    traderaShippingPriceEur: event.target.value,
                  }))
                }
                placeholder='5.00'
                aria-label='Tradera shipping price in EUR'
                title='Tradera shipping price in EUR'
              />
            </FormField>
          </div>
        </FormModal>
      )}
    </div>
  );
}

'use client';

import React from 'react';

import { useSaveCatalogMutation } from '@/features/products/hooks/useProductSettingsQueries';
import type { Language } from '@/shared/contracts/internationalization';
import type { Catalog, PriceGroup } from '@/shared/contracts/products/catalogs';
import { resolvePriceGroupIdentifierToId } from '@/shared/lib/products/utils/price-group-identifiers';
import { useToast } from '@/shared/ui/toast';

import { logClientCatch } from '@/shared/utils/observability/client-error-logger';

interface CatalogFormState {
  name: string;
  description: string;
  isDefault: boolean;
}

interface UseCatalogFormProps {
  catalog?: Catalog | null | undefined;
  languages: Language[];
  priceGroups: PriceGroup[];
  defaultGroupId: string;
}

interface UseCatalogFormReturn {
  form: CatalogFormState;
  setForm: React.Dispatch<React.SetStateAction<CatalogFormState>>;
  selectedLanguageIds: string[];
  setSelectedLanguageIds: React.Dispatch<React.SetStateAction<string[]>>;
  defaultLanguageId: string;
  setDefaultLanguageId: React.Dispatch<React.SetStateAction<string>>;
  catalogPriceGroupIds: string[];
  setCatalogPriceGroupIds: React.Dispatch<React.SetStateAction<string[]>>;
  catalogDefaultPriceGroupId: string;
  setCatalogDefaultPriceGroupId: React.Dispatch<React.SetStateAction<string>>;
  languageQuery: string;
  setLanguageQuery: React.Dispatch<React.SetStateAction<string>>;
  error: string | null;
  setError: React.Dispatch<React.SetStateAction<string | null>>;
  languageIdByAnyValue: Map<string, string>;
  canonicalizeLanguageId: (value: string) => string;
  getLanguage: (value: string) => Language | undefined;
  saveMutation: ReturnType<typeof useSaveCatalogMutation>;
  handleSubmit: () => Promise<void>;
}

const arraysEqual = (a: string[], b: string[]): boolean =>
  a.length === b.length && a.every((value: string, index: number) => value === b[index]);

export function useCatalogForm({
  catalog,
  languages,
  priceGroups,
  defaultGroupId,
}: UseCatalogFormProps): UseCatalogFormReturn {
  const [error, setError] = React.useState<string | null>(null);
  const [form, setForm] = React.useState<CatalogFormState>({
    name: '',
    description: '',
    isDefault: false,
  });
  const [selectedLanguageIds, setSelectedLanguageIds] = React.useState<string[]>([]);
  const [defaultLanguageId, setDefaultLanguageId] = React.useState('');
  const [catalogPriceGroupIds, setCatalogPriceGroupIds] = React.useState<string[]>([]);
  const [catalogDefaultPriceGroupId, setCatalogDefaultPriceGroupId] = React.useState('');
  const [languageQuery, setLanguageQuery] = React.useState('');
  const { toast } = useToast();
  const saveMutation = useSaveCatalogMutation();

  const languageIdByAnyValue = React.useMemo((): Map<string, string> => {
    const map = new Map<string, string>();
    languages.forEach((language: Language) => {
      const id = language.id?.trim();
      const code = language.code?.trim();
      if (id) {
        map.set(id, id);
        map.set(id.toLowerCase(), id);
      }
      if (code && id) {
        map.set(code, id);
        map.set(code.toLowerCase(), id);
      }
    });
    return map;
  }, [languages]);

  const canonicalizeLanguageId = React.useCallback(
    (value: string): string => {
      const trimmed = value.trim();
      if (!trimmed) return '';
      return (
        languageIdByAnyValue.get(trimmed) ??
        languageIdByAnyValue.get(trimmed.toLowerCase()) ??
        trimmed
      );
    },
    [languageIdByAnyValue]
  );

  const getLanguage = React.useCallback(
    (value: string): Language | undefined => {
      const canonicalId = canonicalizeLanguageId(value);
      return languages.find((language: Language) => language.id === canonicalId);
    },
    [canonicalizeLanguageId, languages]
  );

  const canonicalizePriceGroupId = React.useCallback(
    (value: string): string => resolvePriceGroupIdentifierToId(priceGroups, value),
    [priceGroups]
  );

  const normalizePriceGroupIds = React.useCallback(
    (values: string[]): string[] =>
      Array.from(
        new Set(
          values
            .map((value: string) => canonicalizePriceGroupId(value))
            .filter((value: string) => Boolean(value))
        )
      ),
    [canonicalizePriceGroupId]
  );

  React.useEffect(() => {
    const normalizedDefaultGroupId = canonicalizePriceGroupId(defaultGroupId);
    if (catalog) {
      const nextForm = {
        name: catalog.name,
        description: catalog.description ?? '',
        isDefault: catalog.isDefault,
      };
      setForm((previousForm) =>
        previousForm.name === nextForm.name &&
        previousForm.description === nextForm.description &&
        previousForm.isDefault === nextForm.isDefault
          ? previousForm
          : nextForm
      );
      const nextLanguageIds = Array.from(
        new Set((catalog.languageIds ?? []).map((id: string) => canonicalizeLanguageId(id)))
      ).filter((id: string) => Boolean(id));
      setSelectedLanguageIds((previousLanguageIds) =>
        arraysEqual(previousLanguageIds, nextLanguageIds) ? previousLanguageIds : nextLanguageIds
      );
      const normalizedDefaultLanguageId = catalog.defaultLanguageId
        ? canonicalizeLanguageId(catalog.defaultLanguageId)
        : '';
      const nextDefaultLanguageId = nextLanguageIds.includes(normalizedDefaultLanguageId)
        ? normalizedDefaultLanguageId
        : (nextLanguageIds[0] ?? '');
      setDefaultLanguageId((previousDefaultLanguageId) =>
        previousDefaultLanguageId === nextDefaultLanguageId
          ? previousDefaultLanguageId
          : nextDefaultLanguageId
      );
      const nextPriceGroupIds = catalog.priceGroupIds?.length
        ? normalizePriceGroupIds(catalog.priceGroupIds)
        : normalizedDefaultGroupId
          ? [normalizedDefaultGroupId]
          : [];
      const normalizedCatalogDefaultPriceGroupId = catalog.defaultPriceGroupId
        ? canonicalizePriceGroupId(catalog.defaultPriceGroupId)
        : '';
      setCatalogPriceGroupIds((previousPriceGroupIds) =>
        arraysEqual(previousPriceGroupIds, nextPriceGroupIds)
          ? previousPriceGroupIds
          : nextPriceGroupIds
      );
      const nextCatalogDefaultPriceGroupId = nextPriceGroupIds.includes(
        normalizedCatalogDefaultPriceGroupId
      )
        ? normalizedCatalogDefaultPriceGroupId
        : (nextPriceGroupIds[0] ?? normalizedDefaultGroupId ?? '');
      setCatalogDefaultPriceGroupId((previousDefaultPriceGroupId) =>
        previousDefaultPriceGroupId === nextCatalogDefaultPriceGroupId
          ? previousDefaultPriceGroupId
          : nextCatalogDefaultPriceGroupId
      );
    } else {
      const nextForm = {
        name: '',
        description: '',
        isDefault: false,
      };
      setForm((previousForm) =>
        previousForm.name === nextForm.name &&
        previousForm.description === nextForm.description &&
        previousForm.isDefault === nextForm.isDefault
          ? previousForm
          : nextForm
      );
      setSelectedLanguageIds((previousLanguageIds) =>
        previousLanguageIds.length === 0 ? previousLanguageIds : []
      );
      setDefaultLanguageId((previousDefaultLanguageId) =>
        previousDefaultLanguageId === '' ? previousDefaultLanguageId : ''
      );
      const nextPriceGroupIds = normalizedDefaultGroupId ? [normalizedDefaultGroupId] : [];
      setCatalogPriceGroupIds((previousPriceGroupIds) =>
        arraysEqual(previousPriceGroupIds, nextPriceGroupIds)
          ? previousPriceGroupIds
          : nextPriceGroupIds
      );
      setCatalogDefaultPriceGroupId((previousDefaultPriceGroupId) =>
        previousDefaultPriceGroupId === normalizedDefaultGroupId
          ? previousDefaultPriceGroupId
          : normalizedDefaultGroupId
      );
    }
    setError((previousError) => (previousError === null ? previousError : null));
    setLanguageQuery((previousLanguageQuery) =>
      previousLanguageQuery === '' ? previousLanguageQuery : ''
    );
  }, [
    catalog,
    canonicalizeLanguageId,
    canonicalizePriceGroupId,
    defaultGroupId,
    normalizePriceGroupIds,
  ]);

  const handleSubmit = async (): Promise<void> => {
    if (saveMutation.isPending) return;
    const name = form.name.trim();
    const normalizedCatalogPriceGroupIds = normalizePriceGroupIds(catalogPriceGroupIds);
    const normalizedCatalogDefaultPriceGroupId =
      canonicalizePriceGroupId(catalogDefaultPriceGroupId);
    if (!name) {
      toast('Catalog name is required.', { variant: 'error' });
      return;
    }
    if (selectedLanguageIds.length === 0) {
      toast('Select at least one language.', { variant: 'error' });
      return;
    }
    if (!defaultLanguageId || !selectedLanguageIds.includes(defaultLanguageId)) {
      toast('Select a default language.', { variant: 'error' });
      return;
    }
    if (normalizedCatalogPriceGroupIds.length === 0) {
      toast('Select at least one price group.', { variant: 'error' });
      return;
    }
    if (
      !normalizedCatalogDefaultPriceGroupId ||
      !normalizedCatalogPriceGroupIds.includes(normalizedCatalogDefaultPriceGroupId)
    ) {
      toast('Select a default price group.', { variant: 'error' });
      return;
    }

    try {
      await saveMutation.mutateAsync({
        ...(catalog?.id ? { id: catalog.id } : {}),
        data: {
          name,
          description: form.description.trim(),
          languageIds: selectedLanguageIds,
          defaultLanguageId,
          priceGroupIds: normalizedCatalogPriceGroupIds,
          defaultPriceGroupId: normalizedCatalogDefaultPriceGroupId,
          isDefault: form.isDefault,
        },
      });

      toast('Catalog saved.', { variant: 'success' });
    } catch (err) {
      logClientCatch(err, { source: 'CatalogModal', action: 'saveCatalog', catalogId: catalog?.id });
      setError(err instanceof Error ? err.message : 'Failed to save catalog.');
    }
  };

  return {
    form,
    setForm,
    selectedLanguageIds,
    setSelectedLanguageIds,
    defaultLanguageId,
    setDefaultLanguageId,
    catalogPriceGroupIds,
    setCatalogPriceGroupIds,
    catalogDefaultPriceGroupId,
    setCatalogDefaultPriceGroupId,
    languageQuery,
    setLanguageQuery,
    error,
    setError,
    languageIdByAnyValue,
    canonicalizeLanguageId,
    getLanguage,
    saveMutation,
    handleSubmit,
  };
}

'use client';

import { Plus } from 'lucide-react';
import { useCallback, useEffect, useMemo, useState } from 'react';

import type { LabeledOptionDto } from '@/shared/contracts/base';
import {
  useSaveParameterMutation,
  useDeleteParametersMutation,
  useDeleteParameterMutation,
} from '@/features/products/hooks/useProductSettingsQueries';
import type { CatalogRecord } from '@/shared/contracts/products/catalogs';
import {
  PRODUCT_PARAMETER_LINKABLE_SELECTOR_TYPES,
  type ProductParameter,
  type ProductParameterLinkedTitleTermType,
} from '@/shared/contracts/products/parameters';
import { Button } from '@/shared/ui/button';
import { EmptyState } from '@/shared/ui/empty-state';
import { FormSection, FormField } from '@/shared/ui/form-section';
import { FormModal } from '@/shared/ui/FormModal';
import { Input } from '@/shared/ui/input';
import { Checkbox } from '@/shared/ui/checkbox';
import { SelectSimple } from '@/shared/ui/select-simple';
import { ConfirmModal } from '@/shared/ui/templates/modals/ConfirmModal';
import { SimpleSettingsList } from '@/shared/ui/templates/SimpleSettingsList';
import { Textarea } from '@/shared/ui/textarea';
import { useToast } from '@/shared/ui/toast';

import { logClientError } from '@/shared/utils/observability/client-error-logger';

type ParametersSettingsProps = {
  loading: boolean;
  parameters: ProductParameter[];
  catalogs: CatalogRecord[];
  selectedCatalogId: string | null;
  onCatalogChange: (catalogId: string) => void;
  onRefresh: () => void;
};

type ParameterSelectorType = ProductParameter['selectorType'];

type ParameterFormData = {
  name_en: string;
  name_pl: string;
  name_de: string;
  catalogId: string;
  selectorType: ParameterSelectorType;
  optionLabelsInput: string;
  linkedTitleTermType: ProductParameterLinkedTitleTermType;
};

const SELECTOR_TYPE_OPTIONS: Array<LabeledOptionDto<ParameterSelectorType>> = [
  { value: 'text', label: 'Text Field' },
  { value: 'textarea', label: 'Textarea' },
  { value: 'radio', label: 'Radio Buttons' },
  { value: 'select', label: 'Select List' },
  { value: 'dropdown', label: 'Dropdown' },
  { value: 'checklist', label: 'Checklist' },
  { value: 'checkbox', label: 'Checkbox' },
];

const SELECTOR_TYPES_REQUIRING_OPTIONS = new Set<ParameterSelectorType>([
  'radio',
  'select',
  'dropdown',
  'checklist',
]);
const LINKABLE_SELECTOR_TYPES = new Set<ParameterSelectorType>(
  PRODUCT_PARAMETER_LINKABLE_SELECTOR_TYPES
);
const LINKED_TITLE_TERM_OPTIONS: Array<LabeledOptionDto<string>> = [
  { value: '', label: 'No English Title sync' },
  { value: 'size', label: 'Size term' },
  { value: 'material', label: 'Material term' },
  { value: 'theme', label: 'Theme term' },
];

const getLinkedTitleTermLabel = (
  value: ProductParameterLinkedTitleTermType
): string | null => {
  if (!value) return null;
  return LINKED_TITLE_TERM_OPTIONS.find((option) => option.value === value)?.label ?? value;
};

const normalizeOptionLabels = (input: string): string[] => {
  const seen = new Set<string>();
  return input
    .split('\n')
    .flatMap((line: string) => line.split(','))
    .map((value: string) => value.trim())
    .filter((value: string) => {
      if (!value) return false;
      const key = value.toLowerCase();
      if (seen.has(key)) return false;
      seen.add(key);
      return true;
    });
};

const optionLabelsToMultiline = (labels: string[] | null | undefined): string =>
  (labels ?? []).filter(Boolean).join('\n');

const getSelectorTypeLabel = (value: ParameterSelectorType): string =>
  SELECTOR_TYPE_OPTIONS.find((option) => option.value === value)?.label ?? value;

export function ParametersSettings(props: ParametersSettingsProps): React.JSX.Element {
  const { loading, parameters, catalogs, selectedCatalogId, onCatalogChange, onRefresh } = props;

  const { toast } = useToast();
  const [showModal, setShowModal] = useState(false);
  const [editingParameter, setEditingParameter] = useState<ProductParameter | null>(null);
  const [formData, setFormData] = useState<ParameterFormData>({
    name_en: '',
    name_pl: '',
    name_de: '',
    catalogId: '',
    selectorType: 'text',
    optionLabelsInput: '',
    linkedTitleTermType: null,
  });
  const [selectedParameterIds, setSelectedParameterIds] = useState<Set<string>>(new Set());
  const [parameterIdsToDelete, setParameterIdsToDelete] = useState<string[]>([]);

  const saveParameterMutation = useSaveParameterMutation();
  const deleteParametersMutation = useDeleteParametersMutation();
  const deleteParameterMutation = useDeleteParameterMutation();
  const deletePending = deleteParameterMutation.isPending || deleteParametersMutation.isPending;

  const visibleParameterIds = useMemo(
    () => parameters.map((parameter: ProductParameter) => parameter.id),
    [parameters]
  );
  const hasVisibleParameters = visibleParameterIds.length > 0;
  const isAllSelected =
    hasVisibleParameters && selectedParameterIds.size === visibleParameterIds.length;
  const isIndeterminateSelection =
    selectedParameterIds.size > 0 && selectedParameterIds.size < visibleParameterIds.length;
  const parameterIdsToDeleteSet = useMemo(
    () => new Set(parameterIdsToDelete),
    [parameterIdsToDelete]
  );
  const selectAllChecked = isAllSelected
    ? true
    : isIndeterminateSelection
      ? ('indeterminate' as const)
      : false;
  const selectedCount = selectedParameterIds.size;
  const pendingDeleteCount = parameterIdsToDeleteSet.size;

  const clearSelection = useCallback(() => {
    setSelectedParameterIds(new Set());
  }, []);

  useEffect(() => {
    setSelectedParameterIds((prev) => {
      const next = new Set([...prev].filter((id) => visibleParameterIds.includes(id)));
      return next.size === prev.size ? prev : next;
    });
  }, [visibleParameterIds]);

  useEffect(() => {
    clearSelection();
    setParameterIdsToDelete([]);
  }, [clearSelection, selectedCatalogId]);

  const updateSelection = useCallback((parameterId: string, checked: boolean): void => {
    setSelectedParameterIds((prev) => {
      const next = new Set(prev);
      if (checked) {
        next.add(parameterId);
      } else {
        next.delete(parameterId);
      }
      return next;
    });
  }, []);

  const handleToggleSelectAll = useCallback((): void => {
    if (isAllSelected) {
      clearSelection();
      return;
    }
    setSelectedParameterIds(new Set(visibleParameterIds));
  }, [clearSelection, isAllSelected, visibleParameterIds]);

  const startDeleteSelection = useCallback((): void => {
    if (selectedParameterIds.size === 0) {
      toast('Please select at least one parameter to delete.', { variant: 'error' });
      return;
    }
    setParameterIdsToDelete(Array.from(selectedParameterIds));
  }, [selectedParameterIds, toast]);

  const startDeleteParameter = useCallback((parameter: ProductParameter): void => {
    setParameterIdsToDelete([parameter.id]);
  }, []);

  const normalizeSelectionForDeletion = useCallback((): string[] => {
    return Array.from(new Set(parameterIdsToDelete.filter((id) => id.trim())));
  }, [parameterIdsToDelete]);

  const openCreateModal = (): void => {
    if (!selectedCatalogId) {
      toast('Please select a catalog first.', { variant: 'error' });
      return;
    }
    setEditingParameter(null);
    setFormData({
      name_en: '',
      name_pl: '',
      name_de: '',
      catalogId: selectedCatalogId,
      selectorType: 'text',
      optionLabelsInput: '',
      linkedTitleTermType: null,
    });
    setShowModal(true);
  };

  const openEditModal = (parameter: ProductParameter): void => {
    setEditingParameter(parameter);
    setFormData({
      name_en: parameter.name_en,
      name_pl: parameter.name_pl ?? '',
      name_de: parameter.name_de ?? '',
      catalogId: parameter.catalogId,
      selectorType: parameter.selectorType ?? 'text',
      optionLabelsInput: optionLabelsToMultiline(parameter.optionLabels),
      linkedTitleTermType: parameter.linkedTitleTermType ?? null,
    });
    setShowModal(true);
  };

  const handleSave = async (): Promise<void> => {
    if (!formData.name_en.trim()) {
      toast('English name is required.', { variant: 'error' });
      return;
    }
    if (!formData.catalogId) {
      toast('Catalog is required.', { variant: 'error' });
      return;
    }

    const optionLabels = normalizeOptionLabels(formData.optionLabelsInput);
    if (SELECTOR_TYPES_REQUIRING_OPTIONS.has(formData.selectorType) && optionLabels.length === 0) {
      toast('This selector type requires at least one value label.', {
        variant: 'error',
      });
      return;
    }
    if (
      formData.linkedTitleTermType &&
      !LINKABLE_SELECTOR_TYPES.has(formData.selectorType)
    ) {
      toast('Only text and textarea parameters can sync from English Title terms.', {
        variant: 'error',
      });
      return;
    }

    try {
      const payload = {
        name_en: formData.name_en.trim(),
        name_pl: formData.name_pl.trim() || null,
        name_de: formData.name_de.trim() || null,
        catalogId: formData.catalogId,
        selectorType: formData.selectorType,
        optionLabels,
        linkedTitleTermType: formData.linkedTitleTermType,
      };

      await saveParameterMutation.mutateAsync({
        id: editingParameter?.id,
        data: payload,
      });

      toast(editingParameter ? 'Parameter updated.' : 'Parameter created.', {
        variant: 'success',
      });
      setShowModal(false);
      onRefresh();
    } catch (error) {
      logClientError(error);
      const message = error instanceof Error ? error.message : 'Failed to save parameter.';
      toast(message, { variant: 'error' });
    }
  };

  const handleConfirmDelete = async (): Promise<void> => {
    const ids = normalizeSelectionForDeletion();
    if (ids.length === 0) return;
    try {
      if (ids.length === 1) {
        await deleteParameterMutation.mutateAsync({
          id: ids[0]!,
          catalogId: selectedCatalogId,
        });
        toast('Parameter deleted.', { variant: 'success' });
      } else {
        await deleteParametersMutation.mutateAsync({
          parameterIds: ids,
          catalogId: selectedCatalogId,
        });
        const noun = ids.length === 1 ? 'parameter' : 'parameters';
        toast(`Deleted ${ids.length} ${noun}.`, { variant: 'success' });
      }
      onRefresh();
      clearSelection();
    } catch (error) {
      logClientError(error);
      const message = error instanceof Error ? error.message : 'Failed to delete parameter(s).';
      toast(message, { variant: 'error' });
    } finally {
      setParameterIdsToDelete([]);
    }
  };

  const selectedCatalog = catalogs.find(
    (catalog: CatalogRecord): boolean => catalog.id === selectedCatalogId
  );
  const selectorNeedsOptions = SELECTOR_TYPES_REQUIRING_OPTIONS.has(formData.selectorType);
  const selectorSupportsLinking = LINKABLE_SELECTOR_TYPES.has(formData.selectorType);
  const catalogOptions = useMemo<Array<LabeledOptionDto<string>>>(
    () =>
      catalogs.map((catalog: CatalogRecord) => ({
        value: catalog.id,
        label: `${catalog.name}${catalog.isDefault ? ' (Default)' : ''}`,
      })),
    [catalogs]
  );

  return (
    <div className='space-y-5'>
      <FormSection
        title='Select Catalog'
        description='Parameters are managed per catalog.'
        className='p-4'
      >
        <div className='mt-4 w-full max-w-xs'>
          <SelectSimple
            size='sm'
            value={selectedCatalogId || ''}
            onValueChange={onCatalogChange}
            options={catalogOptions}
            placeholder='Select a catalog...'
            ariaLabel='Catalog'
           title='Select a catalog...'/>
        </div>
      </FormSection>

      {selectedCatalogId && (
        <>
          <div className='flex justify-start'>
            <Button onClick={openCreateModal} className='bg-white text-gray-900 hover:bg-gray-200'>
              <Plus className='size-4 mr-2' />
              Add Parameter
            </Button>
          </div>

          <FormSection title={`Parameters for "${selectedCatalog?.name}"`} className='p-4'>
            <div className='mt-4'>
            <div className='mb-4 flex items-center justify-between gap-3'>
              <div className='flex items-center gap-2 text-sm text-gray-300'>
                <Checkbox
                  checked={selectAllChecked}
                  onCheckedChange={() => {
                    handleToggleSelectAll();
                  }}
                  disabled={!hasVisibleParameters || loading}
                  aria-label='Select all parameters'
                  title='Select all parameters'
                />
                <span>Select all</span>
              </div>
              <Button
                size='sm'
                onClick={startDeleteSelection}
                disabled={selectedCount === 0 || deletePending || loading}
                variant='destructive'
                className='gap-2'
              >
                {deletePending ? 'Deleting...' : `Delete Selected (${selectedCount})`}
              </Button>
            </div>
            <SimpleSettingsList
                items={parameters.map((parameter: ProductParameter) => ({
                  id: parameter.id,
                  title: parameter.name_en,
                  subtitle: `Type: ${getSelectorTypeLabel(parameter.selectorType)}`,
                  description: (
                    <div className='flex flex-wrap gap-x-3 gap-y-1'>
                      {parameter.optionLabels.length > 0 && (
                        <span>Options: {parameter.optionLabels.length}</span>
                      )}
                      {parameter.linkedTitleTermType && (
                        <span>Synced: {getLinkedTitleTermLabel(parameter.linkedTitleTermType)}</span>
                      )}
                      {parameter.name_pl && <span>PL: {parameter.name_pl}</span>}
                      {parameter.name_de && <span>DE: {parameter.name_de}</span>}
                    </div>
                  ),
                  original: parameter,
                }))}
                isLoading={loading}
                onEdit={(item) => openEditModal(item.original)}
                renderActions={(item) => (
                  <Checkbox
                    checked={selectedParameterIds.has(item.id)}
                    onCheckedChange={(checked) => {
                      updateSelection(item.id, checked === true);
                    }}
                    aria-label={`Select parameter ${item.title}`}
                    title={`Select parameter ${item.title}`}
                  />
                )}
                onDelete={(item) => {
                  startDeleteParameter(item.original);
                }}
                emptyMessage='No parameters yet. Create product parameters and choose their selector type.'
              />
            </div>
          </FormSection>
        </>
      )}

      {!selectedCatalogId && catalogs.length === 0 && (
        <EmptyState
          title='No catalogs found'
          description='Please create a catalog first in the Catalogs section before adding parameters.'
        />
      )}

      <ConfirmModal
        isOpen={pendingDeleteCount > 0}
        onClose={() => {
          setParameterIdsToDelete([]);
        }}
        onConfirm={handleConfirmDelete}
        title={pendingDeleteCount === 1 ? 'Delete parameter?' : 'Delete parameters?'}
        message={`Delete ${pendingDeleteCount} selected ${
          pendingDeleteCount === 1 ? 'parameter' : 'parameters'
        }? This action cannot be undone and will remove them from all products. `}
        confirmText='Delete'
        isDangerous={true}
        loading={deletePending}
      />

      {showModal && (
        <FormModal
          open={showModal}
          onClose={(): void => setShowModal(false)}
          title={editingParameter ? 'Edit Parameter' : 'Create Parameter'}
          onSave={(): void => {
            void handleSave();
          }}
          isSaving={saveParameterMutation.isPending}
          size='md'
        >
          <div className='space-y-4'>
            <FormField label='Name (EN)'>
              <Input
                value={formData.name_en}
                onChange={(event: React.ChangeEvent<HTMLInputElement>): void =>
                  setFormData((prev: ParameterFormData) => ({
                    ...prev,
                    name_en: event.target.value,
                  }))
                }
                placeholder='Field name in English'
                className='h-9'
               aria-label='Field name in English' title='Field name in English'/>
            </FormField>
            <FormField label='Name (PL)'>
              <Input
                value={formData.name_pl}
                onChange={(event: React.ChangeEvent<HTMLInputElement>): void =>
                  setFormData((prev: ParameterFormData) => ({
                    ...prev,
                    name_pl: event.target.value,
                  }))
                }
                placeholder='Optional'
                className='h-9'
               aria-label='Optional' title='Optional'/>
            </FormField>
            <FormField label='Name (DE)'>
              <Input
                value={formData.name_de}
                onChange={(event: React.ChangeEvent<HTMLInputElement>): void =>
                  setFormData((prev: ParameterFormData) => ({
                    ...prev,
                    name_de: event.target.value,
                  }))
                }
                placeholder='Optional'
                className='h-9'
               aria-label='Optional' title='Optional'/>
            </FormField>
            <FormField label='Selector Type'>
              <SelectSimple
                size='sm'
                value={formData.selectorType}
                onValueChange={(value: string): void =>
                  setFormData((prev: ParameterFormData) => ({
                    ...prev,
                    selectorType: value as ParameterSelectorType,
                    linkedTitleTermType: LINKABLE_SELECTOR_TYPES.has(
                      value as ParameterSelectorType
                    )
                      ? prev.linkedTitleTermType
                      : null,
                  }))
                }
                options={SELECTOR_TYPE_OPTIONS}
                placeholder='Select selector type'
                triggerClassName='w-full bg-gray-900 border-border text-sm text-white h-9'
               ariaLabel='Select selector type' title='Select selector type'/>
            </FormField>
            <FormField label='Linked English Title Term'>
              <SelectSimple
                size='sm'
                value={formData.linkedTitleTermType ?? ''}
                onValueChange={(value: string): void =>
                  setFormData((prev: ParameterFormData) => ({
                    ...prev,
                    linkedTitleTermType:
                      value === '' ? null : (value as ProductParameterLinkedTitleTermType),
                  }))
                }
                options={LINKED_TITLE_TERM_OPTIONS}
                placeholder='No English Title sync'
                disabled={!selectorSupportsLinking}
                triggerClassName='w-full bg-gray-900 border-border text-sm text-white h-9'
               ariaLabel='Linked English Title term' title='Linked English Title term'/>
              <p className='mt-1 text-xs text-gray-500'>
                Automatically maps this parameter from the structured English Title. Available
                for Text Field and Textarea parameters only.
              </p>
            </FormField>
            {selectorNeedsOptions && (
              <FormField label='Option Labels'>
                <Textarea
                  value={formData.optionLabelsInput}
                  onChange={(event: React.ChangeEvent<HTMLTextAreaElement>): void =>
                    setFormData((prev: ParameterFormData) => ({
                      ...prev,
                      optionLabelsInput: event.target.value,
                    }))
                  }
                  className='min-h-[110px] bg-gray-900'
                  placeholder={'One value label per line\nSmall\nMedium\nLarge'}
                 aria-label='One value label per line\nSmall\nMedium\nLarge' title='One value label per line\nSmall\nMedium\nLarge'/>
                <p className='mt-1 text-xs text-gray-500'>
                  Value labels only. Saved labels are exported/imported as plain text values.
                </p>
              </FormField>
            )}
          </div>
        </FormModal>
      )}
    </div>
  );
}

'use client';

import React, { createContext, useContext, useMemo, useState } from 'react';
import {
  useProductSettingsPriceGroupsContext,
  useProductSettingsShippingGroupsContext,
} from '../ProductSettingsContext';
