export interface UseProductMetadataProps {
  product?: ProductWithImages | undefined;
  initialCatalogId?: string | undefined;
  initialCatalogIds?: string[] | undefined;
  initialCategoryId?: string | null | undefined;
  initialTagIds?: string[] | undefined;
  initialProducerIds?: string[] | undefined;
  setValue?: UseFormSetValue<ProductFormData> | undefined;
  getValues?: UseFormGetValues<ProductFormData> | undefined;
}

const toTrimmedString = (value: unknown): string => {
  if (typeof value !== 'string') return '';
  return value.trim();
};

const normalizeSelectionIds = (values: ReadonlyArray<unknown>): string[] => {
  const unique = new Set<string>();
  for (const value of values) {
    const normalizedValue = toTrimmedString(value);
    if (!normalizedValue) continue;
    unique.add(normalizedValue);
  }
  return Array.from(unique);
};

const normalizeCatalogIdList = (values: ReadonlyArray<unknown>): string[] => {
  const resolveCatalogId = (value: unknown): string => {
    if (typeof value === 'string') {
      return toTrimmedString(value);
    }
    if (value === null || value === undefined || typeof value !== 'object') return '';
    const record = value as Record<string, unknown>;
    const direct =
      toTrimmedString(record['catalogId']) ||
      toTrimmedString(record['catalog_id']) ||
      toTrimmedString(record['id']) ||
      toTrimmedString(record['value']);
    if (direct !== '') return direct;

    const nestedCatalog = record['catalog'];
    if (nestedCatalog === null || nestedCatalog === undefined || typeof nestedCatalog !== 'object') return '';
    const nestedRecord = nestedCatalog as Record<string, unknown>;
    const nestedId = toTrimmedString(nestedRecord['id']) ||
      toTrimmedString(nestedRecord['catalogId']) ||
      toTrimmedString(nestedRecord['catalog_id']);
    return nestedId;
  };

  const unique = new Set<string>();
  for (const value of values) {
    const trimmed = resolveCatalogId(value);
    if (trimmed === '') continue;
    unique.add(trimmed);
  }
  return Array.from(unique);
};

const CATALOG_ID_KEY_SEPARATOR = '\u001f';

const resolveCategoryIdFromProduct = (product?: ProductWithImages): string | null => {
  if (product === undefined || product === null) return null;
  const direct = toTrimmedString(product.categoryId);
  if (direct !== '') return direct;
  return null;
};

// Composite hook that combines all metadata functionality
export function useProductMetadata({
  product,
  initialCatalogId,
  initialCatalogIds,
  initialCategoryId,
  initialTagIds,
  initialProducerIds,
}: UseProductMetadataProps): ProductMetadataHookResult {
  const catalogsQuery = useCatalogs();
  const languagesQuery = useLanguages();
  const priceGroupsQuery = usePriceGroups();
  const producersQuery = useProducers();
  const initialCatalogIdsKey = normalizeCatalogIdList(initialCatalogIds ?? []).join(
    CATALOG_ID_KEY_SEPARATOR
  );
  // Initialize selections based on product or initial values
  const initialCatalogSelection = React.useMemo((): string[] => {
    if (product !== undefined && product !== null) {
      const productCatalogIds = Array.isArray(product.catalogs)
        ? normalizeCatalogIdList(product.catalogs)
        : [];
      if (productCatalogIds.length > 0) {
        return productCatalogIds;
      }
      const fallbackCatalogId =
        typeof product.catalogId === 'string' ? product.catalogId.trim() : '';
      if (fallbackCatalogId !== '') {
        return [fallbackCatalogId];
      }
    }
    const normalizedInitialCatalogIds =
      initialCatalogIdsKey === ''
        ? []
        : initialCatalogIdsKey.split(CATALOG_ID_KEY_SEPARATOR).filter(Boolean);
    if (normalizedInitialCatalogIds.length > 0) {
      return normalizedInitialCatalogIds;
    }
    const fallbackInitialCatalogId =
      typeof initialCatalogId === 'string' ? initialCatalogId.trim() : '';
    if (fallbackInitialCatalogId !== '') {
      return [fallbackInitialCatalogId];
    }
    return [];
  }, [product, initialCatalogIdsKey, initialCatalogId]);

  const initialCategorySelection = React.useMemo((): string | null => {
    const resolvedProductCategoryId = resolveCategoryIdFromProduct(product);
    if (resolvedProductCategoryId !== null) {
      return resolvedProductCategoryId;
    }
    if (initialCategoryId !== null && initialCategoryId !== undefined && initialCategoryId !== '') {
      return initialCategoryId;
    }
    return null;
  }, [product, initialCategoryId]);

  const initialTagSelection = React.useMemo((): string[] => {
    if (product?.tags !== undefined && product.tags !== null) {
      return product.tags.map((t: { tagId: string }) => t.tagId);
    }
    return initialTagIds ?? [];
  }, [product, initialTagIds]);

  const initialProducerSelection = React.useMemo((): string[] => {
    if (product?.producers !== undefined && product.producers !== null) {
      return normalizeSelectionIds(
        product.producers.map((p: { producerId: string }) => p.producerId)
      );
    }
    if (initialProducerIds !== undefined && initialProducerIds !== null && initialProducerIds.length > 0) {
      return normalizeSelectionIds(initialProducerIds);
    }
    return [];
  }, [product, initialProducerIds]);

  const [selectedCatalogIds, setSelectedCatalogIds] =
    React.useState<string[]>(initialCatalogSelection);
  const [selectedCategoryId, setSelectedCategoryId] = React.useState<string | null>(
    initialCategorySelection
  );
  const [selectedTagIds, setSelectedTagIds] = React.useState<string[]>(initialTagSelection);
  const [selectedProducerIds, setSelectedProducerIds] =
    React.useState<string[]>(initialProducerSelection);

  const arraysEqual = (a: string[], b: string[]): boolean =>
    a.length === b.length && a.every((value: string, index: number) => value === b[index]);

  React.useEffect(() => {
    setSelectedCatalogIds((prev: string[]) =>
      arraysEqual(prev, initialCatalogSelection) ? prev : initialCatalogSelection
    );
  }, [initialCatalogSelection]);

  React.useEffect(() => {
    setSelectedCategoryId((prev: string | null) =>
      prev === initialCategorySelection ? prev : initialCategorySelection
    );
  }, [initialCategorySelection]);

  React.useEffect(() => {
    setSelectedTagIds((prev: string[]) =>
      arraysEqual(prev, initialTagSelection) ? prev : initialTagSelection
    );
  }, [initialTagSelection]);

  React.useEffect(() => {
    setSelectedProducerIds((prev: string[]) =>
      arraysEqual(prev, initialProducerSelection) ? prev : initialProducerSelection
    );
  }, [initialProducerSelection]);

  const primaryCatalogId = selectedCatalogIds[0] ?? '';
  const categoryTreeCatalogId =
    resolveDefaultProductCategoryTreeCatalogId(catalogsQuery.data ?? []) ??
    (catalogsQuery.isLoading ? null : DEFAULT_PRODUCT_CATEGORY_TREE_CATALOG_ID);
  const categoriesQuery = useCategoriesForCatalogs(
    categoryTreeCatalogId !== null ? [categoryTreeCatalogId] : []
  );
  const shippingGroupsQuery = useShippingGroups(primaryCatalogId);
  const tagsQuery = useTags(primaryCatalogId);
  const parametersQuery = useParameters(primaryCatalogId);
  const categories = categoriesQuery.data ?? [];

  const toggleCatalog = (catalogId: string): void => {
    setSelectedCatalogIds((prev: string[]) =>
      prev.includes(catalogId)
        ? prev.filter((id: string) => id !== catalogId)
        : [...prev, catalogId]
    );
  };

  const setCategoryId = (categoryId: string | null): void => {
    const trimmed = typeof categoryId === 'string' ? categoryId.trim() : '';
    setSelectedCategoryId(trimmed !== '' ? trimmed : null);
  };

  const toggleTag = (tagId: string): void => {
    setSelectedTagIds((prev: string[]) =>
      prev.includes(tagId) ? prev.filter((id: string) => id !== tagId) : [...prev, tagId]
    );
  };

  const toggleProducer = (producerId: string): void => {
    setSelectedProducerIds((prev: string[]) =>
      prev.includes(producerId)
        ? prev.filter((id: string) => id !== producerId)
        : [...prev, producerId]
    );
  };

  const setProducerIds = (producerIds: string[]): void => {
    setSelectedProducerIds((prev: string[]) => {
      const nextIds = normalizeSelectionIds(producerIds);
      return arraysEqual(prev, nextIds) ? prev : nextIds;
    });
  };

  // Derive filtered languages and price groups based on selected catalogs
  const filteredResult = useMemo(() => {
    const catalogs = catalogsQuery.data ?? [];
    const languages = languagesQuery.data ?? [];
    const priceGroups = priceGroupsQuery.data ?? [];

    if (selectedCatalogIds.length === 0) {
      return {
        filteredLanguages: languages,
        filteredPriceGroups: priceGroups,
      };
    }

    const selectedCatalogs = catalogs.filter((catalog: CatalogRecord) =>
      selectedCatalogIds.includes(catalog.id)
    );
    const languageIdSet = new Set(
      selectedCatalogs.flatMap((catalog: CatalogRecord) => catalog.languageIds ?? [])
    );
    const normalizedLanguageSet = new Set(
      Array.from(languageIdSet).map((value: string) => String(value).trim().toUpperCase())
    );

    const languagesResult = languageIdSet.size > 0
      ? languages.filter((language: Language) => {
        const idKey = String(language.id).trim().toUpperCase();
        const codeKey = String(language.code).trim().toUpperCase();
        return normalizedLanguageSet.has(idKey) || normalizedLanguageSet.has(codeKey);
      })
      : languages;

    const priceGroupIdSet = new Set(
      selectedCatalogs.flatMap((catalog: CatalogRecord) => catalog.priceGroupIds ?? [])
    );
    const priceGroupsResult = priceGroupIdSet.size > 0
      ? priceGroups.filter((group: PriceGroupWithDetails) =>
        Array.from(priceGroupIdSet).some((identifier) =>
          matchesPriceGroupIdentifier(group, identifier)
        )
      )
      : priceGroups;

    return { filteredLanguages: languagesResult, filteredPriceGroups: priceGroupsResult };
  }, [catalogsQuery.data, languagesQuery.data, priceGroupsQuery.data, selectedCatalogIds]);

  const { filteredLanguages, filteredPriceGroups } = filteredResult;

  // Guard: detect "form fields invisible" failure condition.
  // Fires only AFTER both catalog and language queries succeed — never during loading.
  useEffect(() => {
    if ((product?.id ?? null) === null) return;
    if (catalogsQuery.isSuccess === false || languagesQuery.isSuccess === false) return;
    if (selectedCatalogIds.length === 0) return;
    if (filteredLanguages.length > 0) return;
    logClientError(new Error('[ProductForm] filteredLanguages empty after queries resolved'), {
      context: {
        service: 'products',
        category: 'form-guard',
        productId: product!.id,
        isHydrated: isEditingProductHydrated(product),
        selectedCatalogIds,
        catalogsCount: catalogsQuery.data?.length ?? 0,
        languagesCount: languagesQuery.data?.length ?? 0,
      },
    });
  }, [
    product,
    catalogsQuery.isSuccess,
    catalogsQuery.data,
    languagesQuery.isSuccess,
    languagesQuery.data,
    selectedCatalogIds,
    filteredLanguages,
  ]);

  return {
    catalogs: catalogsQuery.data ?? [],
    catalogsLoading: catalogsQuery.isLoading,
    catalogsError: ((catalogsQuery.error ?? null) !== null) ? (catalogsQuery.error as Error).message : null,
    selectedCatalogIds,
    toggleCatalog,
    categories,
    categoriesLoading: catalogsQuery.isLoading || categoriesQuery.isLoading,
    selectedCategoryId,
    setCategoryId,
    shippingGroups: shippingGroupsQuery.data ?? [],
    shippingGroupsLoading: shippingGroupsQuery.isLoading,
    tags: tagsQuery.data ?? [],
    tagsLoading: tagsQuery.isLoading,
    selectedTagIds,
    toggleTag,
    producers: producersQuery.data ?? [],
    producersLoading: producersQuery.isLoading,
    selectedProducerIds,
    setProducerIds,
    toggleProducer,
    parameters: parametersQuery.data ?? [],
    parametersLoading: parametersQuery.isLoading,
    filteredLanguages,
    filteredPriceGroups,
  };
}

import type {
  ProductScanAmazonEvaluationStatus,
  ProductScanRecord,
  ProductScanSupplierEvaluationStatus,
  ProductScanStatus,
} from '@/shared/contracts/product-scans';
import type { TriggerButtonRunFeedbackPresentation } from '@/shared/lib/ai-paths/trigger-button-run-feedback';
import { isProductScanActiveStatus } from '@/shared/contracts/product-scans';

export type ProductScanRunFeedback = TriggerButtonRunFeedbackPresentation & {
  scanId: string;
  status: ProductScanStatus;
  updatedAt: string | null;
};

export const PRODUCT_SCAN_CANDIDATE_SELECTION_LABEL = 'Awaiting Selection';
export const PRODUCT_SCAN_CANDIDATE_SELECTION_MESSAGE =
  'Amazon candidates are ready for manual selection.';
export const PRODUCT_SCAN_GOOGLE_STEALTH_RETRY_LABEL = 'Retrying Google';
export const PRODUCT_SCAN_GOOGLE_STEALTH_RETRY_MESSAGE =
  'Retrying Google Lens automatically with a fresh proxy session before manual fallback.';
export const PRODUCT_SCAN_GOOGLE_MANUAL_FALLBACK_LABEL = 'Manual Fallback';
export const PRODUCT_SCAN_GOOGLE_MANUAL_FALLBACK_MESSAGE =
  'Opening a visible browser for Google captcha verification.';

const PRODUCT_SCAN_RUN_FEEDBACK_PRESENTATIONS: Record<
  ProductScanStatus,
  TriggerButtonRunFeedbackPresentation
> = {
  enqueuing: {
    label: 'Enqueuing',
    variant: 'neutral',
    badgeClassName:
      'border-slate-500/40 bg-slate-500/20 text-slate-200 hover:bg-slate-500/25',
  },
  queued: {
    label: 'Queued',
    variant: 'pending',
    badgeClassName:
      'border-amber-500/40 bg-amber-500/20 text-amber-200 hover:bg-amber-500/25',
  },
  running: {
    label: 'Running',
    variant: 'processing',
    badgeClassName:
      'border-cyan-500/40 bg-cyan-500/20 text-cyan-200 hover:bg-cyan-500/25',
  },
  completed: { label: 'Completed', variant: 'success' },
  no_match: {
    label: 'No Match',
    variant: 'warning',
    badgeClassName:
      'border-amber-500/40 bg-amber-500/20 text-amber-200 hover:bg-amber-500/25',
  },
  conflict: {
    label: 'Conflict',
    variant: 'warning',
    badgeClassName:
      'border-orange-500/40 bg-orange-500/20 text-orange-200 hover:bg-orange-500/25',
  },
  failed: { label: 'Failed', variant: 'error' },
};

const isManualVerificationPending = (scan: Pick<ProductScanRecord, 'rawResult'>): boolean => {
  const rawResult = scan.rawResult;
  if (!rawResult || typeof rawResult !== 'object' || Array.isArray(rawResult)) {
    return false;
  }

  return (rawResult as Record<string, unknown>)['manualVerificationPending'] === true;
};

export const isProductScanGoogleStealthRetrying = (
  scan: Pick<ProductScanRecord, 'status' | 'rawResult'> | null | undefined
): boolean => {
  if (scan?.status !== 'running' && scan?.status !== 'queued') {
    return false;
  }

  const rawResult = scan.rawResult;
  if (!rawResult || typeof rawResult !== 'object' || Array.isArray(rawResult)) {
    return false;
  }

  const result = rawResult as Record<string, unknown>;
  return (
    result['captchaStealthRetryStarted'] === true &&
    result['manualVerificationPending'] !== true &&
    result['captchaManualRetryStarted'] !== true
  );
};

export const isProductScanGoogleManualFallbackOpen = (
  scan: Pick<ProductScanRecord, 'status' | 'rawResult' | 'steps'> | null | undefined
): boolean => {
  if (scan?.status !== 'running' && scan?.status !== 'queued') {
    return false;
  }

  const rawResult = scan.rawResult;
  const rawResultRecord =
    rawResult && typeof rawResult === 'object' && !Array.isArray(rawResult)
      ? (rawResult as Record<string, unknown>)
      : null;
  const hasManualRetryFlag = rawResultRecord?.['captchaManualRetryStarted'] === true;
  const hasManualRetryStep =
    Array.isArray(scan.steps) &&
    scan.steps.some((step) => step.key === 'google_manual_retry');

  return hasManualRetryFlag || hasManualRetryStep;
};

const getManualVerificationMessage = (
  scan: Pick<ProductScanRecord, 'rawResult' | 'asinUpdateMessage'> | null | undefined
): string | null => {
  if (!scan) {
    return null;
  }
  const rawResult = scan.rawResult;
  if (rawResult && typeof rawResult === 'object' && !Array.isArray(rawResult)) {
    const msg = (rawResult as Record<string, unknown>)['manualVerificationMessage'];
    if (typeof msg === 'string' && msg.trim().length > 0) {
      return msg;
    }
  }
  return typeof scan.asinUpdateMessage === 'string' ? scan.asinUpdateMessage : null;
};

export const isProductScanCandidateSelectionRequired = (
  scan: Pick<ProductScanRecord, 'status' | 'rawResult'> | null | undefined
): boolean => {
  if (scan?.status !== 'completed') {
    return false;
  }

  const rawResult = scan.rawResult;
  if (!rawResult || typeof rawResult !== 'object' || Array.isArray(rawResult)) {
    return false;
  }

  return (rawResult as Record<string, unknown>)['candidateSelectionRequired'] === true;
};

export const resolveProductScanRunFeedbackPresentation = (
  status: ProductScanStatus,
  options?: {
    manualVerificationPending?: boolean | null;
    manualVerificationMessage?: string | null;
    googleStealthRetrying?: boolean | null;
    googleManualFallbackOpen?: boolean | null;
    candidateSelectionRequired?: boolean | null;
    amazonEvaluationStatus?: ProductScanAmazonEvaluationStatus | null;
    amazonEvaluationLanguageAccepted?: boolean | null;
    supplierEvaluationStatus?: ProductScanSupplierEvaluationStatus | null;
  }
): TriggerButtonRunFeedbackPresentation =>
  (status === 'running' || status === 'queued') && options?.googleStealthRetrying
    ? {
        label: PRODUCT_SCAN_GOOGLE_STEALTH_RETRY_LABEL,
        variant: 'warning',
        badgeClassName:
          'border-amber-500/40 bg-amber-500/20 text-amber-200 hover:bg-amber-500/25',
      }
    : (status === 'running' || status === 'queued') && options?.googleManualFallbackOpen
    ? {
        label: PRODUCT_SCAN_GOOGLE_MANUAL_FALLBACK_LABEL,
        variant: 'warning',
        badgeClassName:
          'border-sky-500/40 bg-sky-500/20 text-sky-200 hover:bg-sky-500/25',
      }
    : status === 'running' && options?.manualVerificationPending
    ? {
        label: /requested login/i.test(options?.manualVerificationMessage ?? '') ? 'Login' : 'Captcha',
        variant: 'warning',
        badgeClassName:
          'border-amber-500/40 bg-amber-500/20 text-amber-200 hover:bg-amber-500/25',
      }
    : status === 'completed' && options?.candidateSelectionRequired
      ? {
          label: PRODUCT_SCAN_CANDIDATE_SELECTION_LABEL,
          variant: 'warning',
          badgeClassName:
            'border-amber-500/40 bg-amber-500/20 text-amber-200 hover:bg-amber-500/25',
        }
    : status === 'no_match' &&
        options?.amazonEvaluationStatus === 'rejected' &&
        options?.amazonEvaluationLanguageAccepted === false
      ? {
          label: 'AI Rejected: Language',
          variant: 'warning',
          badgeClassName:
            'border-orange-500/40 bg-orange-500/20 text-orange-200 hover:bg-orange-500/25',
        }
    : status === 'no_match' && options?.amazonEvaluationStatus === 'rejected'
      ? {
          label: 'AI Rejected',
          variant: 'warning',
          badgeClassName:
            'border-orange-500/40 bg-orange-500/20 text-orange-200 hover:bg-orange-500/25',
        }
      : status === 'no_match' && options?.supplierEvaluationStatus === 'rejected'
        ? {
            label: 'AI Rejected',
            variant: 'warning',
            badgeClassName:
              'border-orange-500/40 bg-orange-500/20 text-orange-200 hover:bg-orange-500/25',
          }
      : status === 'failed' && options?.amazonEvaluationStatus === 'failed'
        ? {
            label: 'AI Failed',
            variant: 'error',
          }
        : status === 'failed' && options?.supplierEvaluationStatus === 'failed'
          ? {
              label: 'AI Failed',
              variant: 'error',
            }
        : PRODUCT_SCAN_RUN_FEEDBACK_PRESENTATIONS[status] ?? {
            label: status,
            variant: 'neutral',
          };

export const buildProductScanRunFeedbackFromRecord = (
  scan: ProductScanRecord
): ProductScanRunFeedback => ({
  scanId: scan.id,
  status: scan.status,
  updatedAt: scan.updatedAt ?? scan.completedAt ?? scan.createdAt ?? null,
  ...resolveProductScanRunFeedbackPresentation(scan.status, {
    manualVerificationPending: isManualVerificationPending(scan),
    manualVerificationMessage: getManualVerificationMessage(scan),
    googleStealthRetrying: isProductScanGoogleStealthRetrying(scan),
    googleManualFallbackOpen: isProductScanGoogleManualFallbackOpen(scan),
    candidateSelectionRequired: isProductScanCandidateSelectionRequired(scan),
    amazonEvaluationStatus: scan.amazonEvaluation?.status ?? null,
    amazonEvaluationLanguageAccepted: scan.amazonEvaluation?.languageAccepted ?? null,
    supplierEvaluationStatus: scan.supplierEvaluation?.status ?? null,
  }),
});

export const resolveProductScanFeedbackAgeMs = (
  scan: ProductScanRecord,
  now = Date.now()
): number => {
  const timestamp = Date.parse(scan.updatedAt ?? scan.completedAt ?? scan.createdAt ?? '');
  if (!Number.isFinite(timestamp)) {
    return Number.POSITIVE_INFINITY;
  }
  return Math.max(0, now - timestamp);
};

export const shouldShowProductScanRunFeedback = (
  scan: ProductScanRecord,
  now = Date.now(),
  terminalTtlMs = 15_000
): boolean => {
  if (isProductScanActiveStatus(scan.status)) {
    return true;
  }
  return resolveProductScanFeedbackAgeMs(scan, now) <= terminalTtlMs;
};

import crypto from 'crypto';

import { type NextRequest } from 'next/server';

import { badRequestError } from '@/shared/errors/app-error';
import { logClientError } from '@/shared/utils/observability/client-error-logger';

const CONTROL_CHARACTERS_PATTERN = /\p{Cc}/gu;

type FileValidationResult = {
  isValid: boolean;
  errors: string[];
  sanitizedName?: string;
  fileHash?: string;
};

type UploadConfig = {
  maxFileSize: number;
  allowedMimeTypes: string[];
  allowedExtensions: string[];
  maxFiles: number;
  requireImageDimensions?: boolean;
  maxWidth?: number;
  maxHeight?: number;
};

export class SecureFileUpload {
  private static readonly DANGEROUS_EXTENSIONS: string[] = [
    '.exe',
    '.bat',
    '.cmd',
    '.com',
    '.pif',
    '.scr',
    '.vbs',
    '.js',
    '.jar',
    '.php',
    '.asp',
    '.aspx',
    '.jsp',
    '.py',
    '.rb',
    '.pl',
    '.sh',
    '.ps1',
  ];

  private static readonly IMAGE_MIME_TYPES: string[] = [
    'image/jpeg',
    'image/jpg',
    'image/png',
    'image/webp',
    'image/gif',
    'image/svg+xml',
  ];

  private static readonly DEFAULT_CONFIG: UploadConfig = {
    maxFileSize: 10 * 1024 * 1024, // 10MB
    allowedMimeTypes: this.IMAGE_MIME_TYPES,
    allowedExtensions: ['.jpg', '.jpeg', '.png', '.webp', '.gif'],
    maxFiles: 5,
    requireImageDimensions: true,
    maxWidth: 4000,
    maxHeight: 4000,
  };

  static async validateFile(
    file: File,
    config: Partial<UploadConfig> = {}
  ): Promise<FileValidationResult> {
    const cfg = { ...this.DEFAULT_CONFIG, ...config };
    const errors: string[] = [];

    // Check file size
    if (file.size > cfg.maxFileSize) {
      errors.push(`File size exceeds ${cfg.maxFileSize / (1024 * 1024)}MB limit`);
    }

    // Check MIME type
    if (!cfg.allowedMimeTypes.includes(file.type)) {
      errors.push(`File type ${file.type} not allowed`);
    }

    // Check file extension
    const extension = this.getFileExtension(file.name).toLowerCase();
    if (!cfg.allowedExtensions.includes(extension)) {
      errors.push(`File extension ${extension} not allowed`);
    }

    // Check for dangerous extensions
    if (this.DANGEROUS_EXTENSIONS.includes(extension)) {
      errors.push('Potentially dangerous file type detected');
    }

    // Validate file name
    const sanitizedName = this.sanitizeFileName(file.name);
    if (!sanitizedName) {
      errors.push('Invalid file name');
    }

    // Check file content (magic bytes)
    const buffer = await file.arrayBuffer();
    const isValidImage = this.validateImageMagicBytes(new Uint8Array(buffer), file.type);
    if (!isValidImage) {
      errors.push('File content does not match declared type');
    }

    // Generate file hash for deduplication
    const fileHash = await this.generateFileHash(buffer);

    // Check image dimensions if required
    if (cfg.requireImageDimensions && this.IMAGE_MIME_TYPES.includes(file.type)) {
      try {
        const dimensions = this.getImageDimensions(buffer);
        if (cfg.maxWidth && dimensions.width > cfg.maxWidth) {
          errors.push(`Image width ${dimensions.width}px exceeds ${cfg.maxWidth}px limit`);
        }
        if (cfg.maxHeight && dimensions.height > cfg.maxHeight) {
          errors.push(`Image height ${dimensions.height}px exceeds ${cfg.maxHeight}px limit`);
        }
      } catch (error) {
        logClientError(error);
        errors.push('Unable to read image dimensions');
      }
    }

    return {
      isValid: errors.length === 0,
      errors,
      sanitizedName,
      fileHash,
    };
  }

  static async validateMultipleFiles(
    files: File[],
    config: Partial<UploadConfig> = {}
  ): Promise<{
    isValid: boolean;
    results: Array<FileValidationResult & { fileName: string }>;
    globalErrors: string[];
  }> {
    const cfg = { ...this.DEFAULT_CONFIG, ...config };
    const globalErrors: string[] = [];

    // Check file count
    if (files.length > cfg.maxFiles) {
      globalErrors.push(`Too many files. Maximum ${cfg.maxFiles} allowed`);
    }

    // Check total size
    const totalSize = files.reduce((sum: number, file: File) => sum + file.size, 0);
    const maxTotalSize = cfg.maxFileSize * cfg.maxFiles;
    if (totalSize > maxTotalSize) {
      globalErrors.push(`Total file size exceeds ${maxTotalSize / (1024 * 1024)}MB limit`);
    }

    // Validate each file
    const results = await Promise.all(
      files.map(async (file: File) => ({
        fileName: file.name,
        ...(await this.validateFile(file, config)),
      }))
    );

    // Check for duplicate files
    const hashes = results.map((r: FileValidationResult) => r.fileHash).filter(Boolean);
    const duplicates = hashes.filter(
      (hash: string | undefined, index: number) => hashes.indexOf(hash) !== index
    );
    if (duplicates.length > 0) {
      globalErrors.push('Duplicate files detected');
    }

    return {
      isValid: globalErrors.length === 0 && results.every((r: FileValidationResult) => r.isValid),
      results,
      globalErrors,
    };
  }

  private static getFileExtension(fileName: string): string {
    const lastDot = fileName.lastIndexOf('.');
    return lastDot === -1 ? '' : fileName.substring(lastDot);
  }

  private static sanitizeFileName(fileName: string): string {
    // Remove path traversal attempts
    let sanitized = fileName.replace(/[/\\:*?"<>|]/g, '');

    // Remove null bytes and control characters
    sanitized = sanitized.replace(CONTROL_CHARACTERS_PATTERN, '');

    // Limit length
    if (sanitized.length > 255) {
      const ext = this.getFileExtension(sanitized);
      const nameWithoutExt = sanitized.substring(0, sanitized.lastIndexOf('.'));
      sanitized = nameWithoutExt.substring(0, 255 - ext.length) + ext;
    }

    // Ensure it's not empty or just dots
    if (!sanitized || /^\.+$/.test(sanitized)) {
      return '';
    }

    return sanitized;
  }

  private static validateImageMagicBytes(bytes: Uint8Array, mimeType: string): boolean {
    const signatures: Record<string, number[][]> = {
      'image/jpeg': [[0xff, 0xd8, 0xff]],
      'image/png': [[0x89, 0x50, 0x4e, 0x47, 0x0d, 0x0a, 0x1a, 0x0a]],
      'image/gif': [
        [0x47, 0x49, 0x46, 0x38, 0x37, 0x61],
        [0x47, 0x49, 0x46, 0x38, 0x39, 0x61],
      ],
      'image/webp': [
        [0x52, 0x49, 0x46, 0x46],
        [0x57, 0x45, 0x42, 0x50],
      ],
      'image/svg+xml': [
        [0x3c, 0x3f, 0x78, 0x6d, 0x6c],
        [0x3c, 0x73, 0x76, 0x67],
      ],
    };

    const sigs = signatures[mimeType];
    if (!sigs) return false;

    return sigs.some((sig: number[]) =>
      sig.every((byte: number, index: number) => bytes[index] === byte)
    );
  }

  private static async generateFileHash(buffer: ArrayBuffer): Promise<string> {
    const hashBuffer = await crypto.subtle.digest('SHA-256', buffer);
    const hashArray = Array.from(new Uint8Array(hashBuffer));
    return hashArray.map((b: number) => b.toString(16).padStart(2, '0')).join('');
  }

  private static getImageDimensions(buffer: ArrayBuffer): { width: number; height: number } {
    const bytes = new Uint8Array(buffer);

    // PNG: magic bytes 89 50 4E 47, IHDR chunk at offset 8 contains width/height
    if (bytes[0] === 0x89 && bytes[1] === 0x50) {
      if (bytes.length < 24) throw badRequestError('Invalid PNG buffer');
      const width = (bytes[16]! << 24) | (bytes[17]! << 16) | (bytes[18]! << 8) | bytes[19]!;
      const height = (bytes[20]! << 24) | (bytes[21]! << 16) | (bytes[22]! << 8) | bytes[23]!;
      return { width, height };
    }

    // JPEG: scan for SOF (Start Of Frame) marker to read real dimensions
    if (bytes[0] === 0xff && bytes[1] === 0xd8) {
      let i = 2;
      while (i + 1 < bytes.length) {
        if (bytes[i] !== 0xff) break;
        const marker = bytes[i + 1]!;
        // SOF markers C0–CF encode image dimensions, except:
        //   C4 = DHT (Huffman table), C8 = JPEG extension, CC = DAC
        if (
          marker >= 0xc0 &&
          marker <= 0xcf &&
          marker !== 0xc4 &&
          marker !== 0xc8 &&
          marker !== 0xcc
        ) {
          // SOF layout: FF Cx <length 2B> <precision 1B> <height 2B> <width 2B>
          if (i + 8 >= bytes.length) break;
          const height = (bytes[i + 5]! << 8) | bytes[i + 6]!;
          const width = (bytes[i + 7]! << 8) | bytes[i + 8]!;
          if (width > 0 && height > 0) return { width, height };
        }
        // EOI — end of image
        if (marker === 0xd9) break;
        // Markers without a length field: RST0–RST7 (D0–D7), SOI (D8), EOI (D9), TEM (01)
        if (marker === 0x01 || (marker >= 0xd0 && marker <= 0xd9)) {
          i += 2;
          continue;
        }
        // All other markers carry a 2-byte length field (the length includes itself)
        if (i + 3 >= bytes.length) break;
        const segLength = (bytes[i + 2]! << 8) | bytes[i + 3]!;
        if (segLength < 2) break;
        i += 2 + segLength;
      }
      throw badRequestError('Could not parse JPEG dimensions');
    }

    throw badRequestError('Unsupported image format for dimension reading');
  }
}

// Middleware for secure file upload
export async function withSecureFileUpload(
  req: NextRequest,
  config?: Partial<UploadConfig>
): Promise<{
  isValid: boolean;
  files?: File[];
  errors: string[];
  sanitizedFiles?: Array<{ file: File; sanitizedName: string; hash: string }>;
}> {
  try {
    const formData = await req.formData();
    const files: File[] = [];

    // Extract files from form data
    for (const [_key, value] of formData.entries()) {
      if (value instanceof File) {
        files.push(value);
      }
    }

    if (files.length === 0) {
      return { isValid: false, errors: ['No files provided'] };
    }

    const validation = await SecureFileUpload.validateMultipleFiles(files, config);

    if (!validation.isValid) {
      const allErrors = [
        ...validation.globalErrors,
        ...validation.results.flatMap((r: FileValidationResult) => r.errors),
      ];
      return { isValid: false, errors: allErrors };
    }

    const sanitizedFiles = validation.results.map(
      (result: FileValidationResult, index: number) => ({
        file: files[index]!,
        sanitizedName: result.sanitizedName!,
        hash: result.fileHash!,
      })
    );

    return {
      isValid: true,
      files,
      errors: [],
      sanitizedFiles,
    };
  } catch (error) {
    logClientError(error);
    return {
      isValid: false,
      errors: ['Failed to process file upload'],
    };
  }
}

