      value:
        typeof evaluation?.imageMatch === 'boolean' ? String(evaluation.imageMatch) : null,
    },
    {
      label: 'Description match',
      value:
        typeof evaluation?.descriptionMatch === 'boolean'
          ? String(evaluation.descriptionMatch)
          : null,
