const amazonScanRuntime = requireProductScanNativeRuntime(AMAZON_PRODUCT_SCAN_PROVIDER);
const AMAZON_PRODUCT_SCAN_RUNTIME_KEYS = new Set<string>([
  AMAZON_REVERSE_IMAGE_SCAN_RUNTIME_KEY,
  AMAZON_GOOGLE_LENS_CANDIDATE_SEARCH_RUNTIME_KEY,
  AMAZON_CANDIDATE_EXTRACTION_RUNTIME_KEY,
]);

const resolveAmazonScanRuntimeKey = (
  scan: ProductScanRecord
): typeof AMAZON_REVERSE_IMAGE_SCAN_RUNTIME_KEY | typeof AMAZON_GOOGLE_LENS_CANDIDATE_SEARCH_RUNTIME_KEY | typeof AMAZON_CANDIDATE_EXTRACTION_RUNTIME_KEY => {
  const rawRuntimeKey = readOptionalString(toRecord(scan.rawResult)?.['runtimeKey'], 160);
  return rawRuntimeKey !== null && AMAZON_PRODUCT_SCAN_RUNTIME_KEYS.has(rawRuntimeKey)
    ? (rawRuntimeKey as typeof AMAZON_REVERSE_IMAGE_SCAN_RUNTIME_KEY | typeof AMAZON_GOOGLE_LENS_CANDIDATE_SEARCH_RUNTIME_KEY | typeof AMAZON_CANDIDATE_EXTRACTION_RUNTIME_KEY)
    : AMAZON_REVERSE_IMAGE_SCAN_RUNTIME_KEY;
};

const resolveAmazonScanRuntimeAction = (
  scan: ProductScanRecord
): Promise<PlaywrightAction | null> =>
  resolveAmazonRuntimeActionDefinition(resolveAmazonScanRuntimeKey(scan));

const resolveLatestGoogleCandidatesStep = (
  steps: ReturnType<typeof parseAmazonScanRuntimeResult>['steps']
) => {
  for (let index = steps.length - 1; index >= 0; index -= 1) {
    const step = steps[index];
    if (step?.key === 'google_candidates') {
      return step;
    }
  }

  return null;
};

const isGoogleCandidatesNoCandidatesFailure = (
  parsedResult: ReturnType<typeof parseAmazonScanRuntimeResult>
): boolean => {
  const latestGoogleCandidatesStep = resolveLatestGoogleCandidatesStep(parsedResult.steps);
  if (
    latestGoogleCandidatesStep?.status === 'failed' &&
    latestGoogleCandidatesStep.resultCode === 'no_candidates'
  ) {
    return true;
  }

  if (parsedResult.stage !== 'google_candidates') {
    return false;
  }

  const normalizedMessage = readOptionalString(parsedResult.message)?.toLowerCase() ?? '';
  return (
    normalizedMessage.includes('no amazon candidates found') ||
    normalizedMessage.includes('did not contain any amazon product urls')
  );
};

const retryAmazonScanWithFallbackProviderAfterNoCandidates = async (input: {
  scan: ProductScanRecord;
  run: PlaywrightEngineRunRecord;
  engineRunId: string;
  resultValue: unknown;
  parsedResult: ReturnType<typeof parseAmazonScanRuntimeResult>;
  currentAmazonRuntimeKey: ReturnType<typeof resolveAmazonScanRuntimeKey>;
  currentAmazonRuntimeAction: PlaywrightAction | null;
  requestedStepSequenceInput: ReturnType<typeof resolveProductScanRequestSequenceInput>;
  persistedAmazonProbe: ProductScanRecord['amazonProbe'];
  existingAmazonEvaluation: ProductScanRecord['amazonEvaluation'];
}): Promise<ProductScanRecord | null> => {
  if (input.currentAmazonRuntimeKey === AMAZON_CANDIDATE_EXTRACTION_RUNTIME_KEY) {
    return null;
  }

  let scannerSettings = createDefaultProductScannerSettings();
  try {
    scannerSettings = (await getProductScannerSettings()) ?? scannerSettings;
  } catch (error) {
    void ErrorSystem.captureException(error, {
      service: 'product-scans.service',
      action: 'synchronizeProductScan.loadScannerSettingsForGoogleCandidatesFallback',
      scanId: input.scan.id,
      productId: input.scan.productId,
      engineRunId: input.engineRunId,
    });
  }

  const amazonImageSearchProvider = resolveAmazonImageSearchProvider(
    input.scan.rawResult,
    scannerSettings
  );
  const fallbackProvider = resolveAmazonImageSearchFallbackProvider({
    rawResult: input.scan.rawResult,
    scannerSettings,
    currentProvider: amazonImageSearchProvider,
    imageCandidates: input.scan.imageCandidates,
  });
  if (!fallbackProvider) {
    return null;
  }

  try {
    const product = await productService.getProductById(input.scan.productId);
    if (!product) {
      return null;
    }

    const scannerEngineRequestOptions =
      buildProductScannerEngineRequestOptions(scannerSettings);
    const scannerRuntimeOptions = buildAmazonScannerRequestRuntimeOptions({
      scannerSettings,
      scannerEngineRequestOptions,
      actionExecutionSettings: input.currentAmazonRuntimeAction?.executionSettings ?? null,
      actionPersonaId: input.currentAmazonRuntimeAction?.personaId ?? null,
      runtimeKey: input.currentAmazonRuntimeKey,
    });
    const manualVerificationTimeoutMs =
      resolveScanManualVerificationTimeoutMs(scannerSettings);
    const amazonSelectorProfile =
      readOptionalString(toRecord(input.scan.rawResult)?.['selectorProfile'], 120) ?? 'amazon';
    const providerHistory = resolveAmazonImageSearchProviderHistory(
      input.scan.rawResult,
      amazonImageSearchProvider
    );
    const amazonImageSearchPageUrl = resolveAmazonImageSearchPageUrl(
      input.scan.rawResult,
      scannerSettings
    );
    const triageEvaluatorEnabled = (
      await resolveAmazonTriageEvaluatorConfig(scannerSettings)
    ).enabled;
    const probeEvaluatorEnabled = (
      await resolveAmazonProbeEvaluatorConfig(scannerSettings)
    ).enabled;
    const isCandidateSearchRuntime =
      input.currentAmazonRuntimeKey === AMAZON_GOOGLE_LENS_CANDIDATE_SEARCH_RUNTIME_KEY;
    const fallbackRun = await startPlaywrightEngineTask({
      request: {
        runtimeKey: input.currentAmazonRuntimeKey,
        actionId: input.currentAmazonRuntimeAction?.id ?? null,
        actionName:
          input.currentAmazonRuntimeAction?.name ??
          resolveAmazonRuntimeActionName(input.currentAmazonRuntimeKey),
        selectorProfile: amazonSelectorProfile,
        input: amazonScanRuntime.buildRequestInput({
          productId: product.id,
          productName: input.scan.productName,
          existingAsin: product.asin,
          imageCandidates: input.scan.imageCandidates,
          runtimeKey: input.currentAmazonRuntimeKey,
          imageSearchProvider: fallbackProvider,
          imageSearchPageUrl: amazonImageSearchPageUrl,
          selectorProfile: amazonSelectorProfile,
          allowManualVerification:
            shouldAutoShowScannerCaptchaBrowser(scannerSettings),
          manualVerificationTimeoutMs,
          triageOnlyOnAmazonCandidates:
            isCandidateSearchRuntime ? false : triageEvaluatorEnabled,
          collectAmazonCandidatePreviews: isCandidateSearchRuntime,
          probeOnlyOnAmazonMatch:
            isCandidateSearchRuntime ? false : probeEvaluatorEnabled,
          skipAmazonProbe: false,
          ...input.requestedStepSequenceInput,
        }),
        timeoutMs: resolveAmazonScanRuntimeTimeoutMs({
          allowManualVerification: shouldAutoShowScannerCaptchaBrowser(scannerSettings),
          manualVerificationTimeoutMs,
        }),
        browserEngine: 'chromium',
        ...scannerRuntimeOptions,
        capture: resolveAmazonScanDiagnosticCapture(input.scan.rawResult),
        preventNewPages: true,
      },
      ownerUserId: input.scan.updatedBy?.trim() || null,
      instance: createCustomPlaywrightInstance({
        family: 'scrape',
        label: 'Amazon fallback provider scan',
        tags: ['product', 'amazon', 'scan', 'provider-fallback'],
      }),
    });

    const fallbackStatus = fallbackRun.status === 'running' ? 'running' : 'queued';
    const nextSteps = resolvePersistedProductScanSteps(input.scan, input.parsedResult.steps);
    return await persistSynchronizedScan(input.scan, {
      engineRunId: fallbackRun.runId,
      status: fallbackStatus,
      asin: null,
      matchedImageId: input.parsedResult.matchedImageId,
      title: null,
      price: null,
      url: null,
      description: null,
      amazonDetails: null,
      amazonProbe: input.persistedAmazonProbe,
      amazonEvaluation: input.existingAmazonEvaluation,
      steps: upsertPersistedProductScanStep(nextSteps, {
        key: 'queue_scan',
        label: 'Retry with fallback image-search provider',
        group: 'input',
        attempt: resolveNextQueueStepAttempt(nextSteps),
        status: 'completed',
        resultCode: fallbackStatus === 'running' ? 'run_started' : 'run_queued',
        message:
          fallbackStatus === 'running'
            ? 'Started an Amazon scan with the fallback image-search provider.'
            : 'Queued an Amazon scan with the fallback image-search provider.',
        details: [
          { label: 'Previous provider', value: amazonImageSearchProvider },
          { label: 'Fallback provider', value: fallbackProvider },
          { label: 'Reason', value: 'Google Lens returned no Amazon candidate URLs.' },
        ],
        url: null,
      }),
      rawResult: {
        ...createProductScanStartedRawResult({
          runId: fallbackRun.runId,
          status: fallbackRun.status,
          runtimeKey: input.currentAmazonRuntimeKey,
          actionId: input.currentAmazonRuntimeAction?.id ?? null,
          selectorProfile: amazonSelectorProfile,
          imageSearchProvider: fallbackProvider,
          imageSearchPageUrl: amazonImageSearchPageUrl,
          imageSearchProviderHistory: [...providerHistory, fallbackProvider],
          allowManualVerification:
            shouldAutoShowScannerCaptchaBrowser(scannerSettings),
          manualVerificationTimeoutMs,
          previousRunId: input.engineRunId,
          previousResult: input.resultValue,
          recordDiagnostics:
            resolveAmazonScanDiagnosticCapture(input.scan.rawResult).trace === true,
          ...input.requestedStepSequenceInput,
        }),
        providerFallback: true,
        fallbackFromImageSearchProvider: amazonImageSearchProvider,
        fallbackToImageSearchProvider: fallbackProvider,
        fallbackTriggerStage: 'google_candidates',
      },
      error: null,
      asinUpdateStatus: 'pending',
      asinUpdateMessage: null,
      completedAt: null,
    });
  } catch (error) {
    void ErrorSystem.captureException(error, {
      service: 'product-scans.service',
      action: 'synchronizeProductScan.retryGoogleCandidatesFallback',
      scanId: input.scan.id,
      productId: input.scan.productId,
      engineRunId: input.engineRunId,
    });
    return null;
  }
};

const retryAmazonScanWithNextCandidateAfterAmazonStageFailure = async (input: {
  scan: ProductScanRecord;
  run: PlaywrightEngineRunRecord;
  engineRunId: string;
  resultValue: unknown;
  parsedResult: ReturnType<typeof parseAmazonScanRuntimeResult>;
  currentAmazonRuntimeKey: ReturnType<typeof resolveAmazonScanRuntimeKey>;
  currentAmazonRuntimeAction: PlaywrightAction | null;
  requestedStepSequenceInput: ReturnType<typeof resolveProductScanRequestSequenceInput>;
  persistedAmazonProbe: ProductScanRecord['amazonProbe'];
  existingAmazonEvaluation: ProductScanRecord['amazonEvaluation'];
  finalUrl: string | null;
  diagnosticsEnabled: boolean;
}): Promise<ProductScanRecord | null> => {
  const failedStage = readOptionalString(input.parsedResult.stage, 120);
  if (failedStage === null || failedStage.startsWith('amazon_') === false) {
    return null;
  }

  const currentCandidateUrl = resolvePersistableScanUrl(
    input.parsedResult.url,
    input.parsedResult.currentUrl,
    input.finalUrl
  );
  const nextCandidate = resolveNextAmazonCandidateUrl({
    candidateUrls: input.parsedResult.candidateUrls,
    currentUrl: currentCandidateUrl,
  });
  if (nextCandidate.nextUrl === null || nextCandidate.nextRank === null) {
    return null;
  }

  let scannerSettings = createDefaultProductScannerSettings();
  try {
    scannerSettings = (await getProductScannerSettings()) ?? scannerSettings;
  } catch (error) {
    void ErrorSystem.captureException(error, {
      service: 'product-scans.service',
      action: 'synchronizeProductScan.loadScannerSettingsForAmazonStageContinuation',
      scanId: input.scan.id,
      productId: input.scan.productId,
      engineRunId: input.engineRunId,
    });
  }

  const product = await productService.getProductById(input.scan.productId);
  if (!product) {
    return null;
  }

  const scannerEngineRequestOptions =
    buildProductScannerEngineRequestOptions(scannerSettings);
  const scannerRuntimeOptions = buildAmazonScannerRequestRuntimeOptions({
    scannerSettings,
    scannerEngineRequestOptions,
    actionExecutionSettings: input.currentAmazonRuntimeAction?.executionSettings ?? null,
    actionPersonaId: input.currentAmazonRuntimeAction?.personaId ?? null,
    runtimeKey: input.currentAmazonRuntimeKey,
  });
  const manualVerificationTimeoutMs =
    resolveScanManualVerificationTimeoutMs(scannerSettings);
  const amazonImageSearchProvider = resolveAmazonImageSearchProvider(
    input.scan.rawResult,
    scannerSettings
  );
  const amazonImageSearchPageUrl = resolveAmazonImageSearchPageUrl(
    input.scan.rawResult,
    scannerSettings
  );
  const amazonSelectorProfile =
    readOptionalString(toRecord(input.scan.rawResult)?.['selectorProfile'], 120) ?? 'amazon';
  const continuationRun = await startPlaywrightEngineTask({
    request: {
      runtimeKey: input.currentAmazonRuntimeKey,
      actionId: input.currentAmazonRuntimeAction?.id ?? null,
      actionName:
        input.currentAmazonRuntimeAction?.name ??
        resolveAmazonRuntimeActionName(input.currentAmazonRuntimeKey),
      selectorProfile: amazonSelectorProfile,
      input: amazonScanRuntime.buildRequestInput({
        productId: product.id,
        productName: input.scan.productName,
        existingAsin: product.asin,
        imageCandidates: input.scan.imageCandidates,
        runtimeKey: input.currentAmazonRuntimeKey,
        imageSearchProvider: amazonImageSearchProvider,
        imageSearchPageUrl: amazonImageSearchPageUrl,
        selectorProfile: amazonSelectorProfile,
        allowManualVerification:
          shouldAutoShowScannerCaptchaBrowser(scannerSettings),
        manualVerificationTimeoutMs,
        probeOnlyOnAmazonMatch: false,
        skipAmazonProbe: false,
        directAmazonCandidateUrl: nextCandidate.nextUrl,
        directAmazonCandidateUrls: nextCandidate.remainingCandidateUrls,
        directMatchedImageId: input.parsedResult.matchedImageId,
        directAmazonCandidateRank: nextCandidate.nextRank,
        ...input.requestedStepSequenceInput,
      }),
      timeoutMs: resolveAmazonScanRuntimeTimeoutMs({
        allowManualVerification: shouldAutoShowScannerCaptchaBrowser(scannerSettings),
        manualVerificationTimeoutMs,
      }),
      browserEngine: 'chromium',
      ...scannerRuntimeOptions,
      capture: resolveAmazonScanDiagnosticCapture(input.scan.rawResult),
      preventNewPages: true,
    },
    ownerUserId: input.scan.updatedBy?.trim() || null,
    instance: createCustomPlaywrightInstance({
      family: 'scrape',
      label: 'Amazon failed-candidate continuation scan',
      tags: ['product', 'amazon', 'scan', 'candidate-continuation'],
    }),
  });

  const continuationStatus = continuationRun.status === 'running' ? 'running' : 'queued';
  const nextSteps = resolvePersistedProductScanSteps(input.scan, input.parsedResult.steps);
  return await persistSynchronizedScan(input.scan, {
    engineRunId: continuationRun.runId,
    status: continuationStatus,
    asin: null,
    matchedImageId: input.parsedResult.matchedImageId,
    title: null,
    price: null,
    url: nextCandidate.nextUrl,
    description: null,
    amazonDetails: null,
    amazonProbe: input.persistedAmazonProbe,
    amazonEvaluation: input.existingAmazonEvaluation,
    steps: upsertPersistedProductScanStep(nextSteps, {
      key: 'queue_scan',
      label: 'Continue with next Amazon candidate',
      group: 'input',
      attempt: resolveNextQueueStepAttempt(nextSteps),
      status: 'completed',
      resultCode: continuationStatus === 'running' ? 'run_started' : 'run_queued',
      message:
        continuationStatus === 'running'
          ? 'Started the next Amazon candidate after candidate-page failure.'
          : 'Queued the next Amazon candidate after candidate-page failure.',
      details: [
        { label: 'Failure stage', value: failedStage },
        { label: 'Rejected candidate URL', value: currentCandidateUrl },
        { label: 'Next candidate URL', value: nextCandidate.nextUrl },
      ],
      url: nextCandidate.nextUrl,
    }),
    rawResult: {
      ...createProductScanStartedRawResult({
        runId: continuationRun.runId,
        status: continuationRun.status,
        runtimeKey: input.currentAmazonRuntimeKey,
        actionId: input.currentAmazonRuntimeAction?.id ?? null,
        selectorProfile: amazonSelectorProfile,
        imageSearchProvider: amazonImageSearchProvider,
        imageSearchPageUrl: amazonImageSearchPageUrl,
        imageSearchProviderHistory: resolveAmazonImageSearchProviderHistory(
          input.scan.rawResult,
          amazonImageSearchProvider
        ),
        allowManualVerification:
          shouldAutoShowScannerCaptchaBrowser(scannerSettings),
        manualVerificationTimeoutMs,
        previousRunId: input.engineRunId,
        previousResult: input.resultValue,
        recordDiagnostics: input.diagnosticsEnabled,
        ...input.requestedStepSequenceInput,
      }),
      candidateContinuation: true,
      continuationCandidateUrls: nextCandidate.remainingCandidateUrls,
      continuationReason: 'candidate_page_failure',
      failedCandidateStage: failedStage,
    },
    error: null,
    asinUpdateStatus: 'pending',
    asinUpdateMessage: null,
    completedAt: null,
  });
};

export async function synchronizeAmazonProductScan(
  scan: ProductScanRecord
): Promise<ProductScanRecord> {
  const engineRunId = resolveScanEngineRunId(scan);

  if (!engineRunId) {
    const ageMs =
      resolveIsoAgeMs(scan.updatedAt) ??
      resolveIsoAgeMs(scan.createdAt) ??
      resolveIsoAgeMs(scan.completedAt);
    if (ageMs != null && ageMs >= PRODUCT_SCAN_ORPHANED_ACTIVE_MAX_AGE_MS) {
      return await persistFailedSynchronization(
        scan,
        'Amazon scan is missing its Playwright engine run id.'
      );
    }

    return scan;
  }

  try {
    let run: PlaywrightEngineRunRecord | null;
    try {
      run = await readPlaywrightEngineRun(engineRunId);
    } catch (error) {
      void ErrorSystem.captureException(error, {
        service: 'product-scans.service',
        action: 'synchronizeProductScan.readRun',
        scanId: scan.id,
        productId: scan.productId,
        engineRunId,
      });
      return scan;
    }

    if (!run) {
      const message = `Playwright engine run ${engineRunId} was not found.`;
      return await persistFailedSynchronization(scan, message);
    }

    const { resultValue, finalUrl } = resolvePlaywrightEngineRunOutputs(run.result);
    const parsedResult = parseAmazonScanRuntimeResult(resultValue);
    const diagnostics = createAmazonScanDiagnosticEmitter(scan);
    if (diagnostics.enabled) {
      const runArtifacts = await collectAmazonScanRunDiagnosticArtifacts(run);
      await diagnostics.emit('sync.enter', {
        'run-metadata': amazonScanDiagnosticArtifact.json({
          engineRunId,
          status: run.status,
          startedAt: run.startedAt,
          completedAt: run.completedAt,
          finalUrl,
        }),
        'parsed-result': amazonScanDiagnosticArtifact.json(parsedResult),
        'raw-engine-result': amazonScanDiagnosticArtifact.json(resultValue),
        'scan-snapshot': amazonScanDiagnosticArtifact.json({
          id: scan.id,
          productId: scan.productId,
          status: scan.status,
          provider: scan.provider,
          rawResult: scan.rawResult,
        }),
        ...runArtifacts,
      });
    }
    const currentAmazonRuntimeKey = resolveAmazonScanRuntimeKey(scan);
    const currentAmazonRuntimeAction = await resolveAmazonScanRuntimeAction(scan);
    const requestedStepSequenceInput = resolveProductScanRequestSequenceInput(scan.rawResult);
    const existingAmazonEvaluation = scan.amazonEvaluation ?? null;
    const approvedCandidateProbe =
      isApprovedAmazonCandidateExtractionRun(scan) ? scan.amazonProbe ?? null : null;
    const persistedAmazonProbe = parsedResult.amazonProbe ?? approvedCandidateProbe;

    if (run.status === 'queued' || run.status === 'running') {
      const existingRawResult = toRecord(scan.rawResult) ?? {};
      const manualVerificationTimeoutMs = resolveScanManualVerificationTimeoutMs(
        existingRawResult
      );
      const activeRunDiagnostics = buildAmazonActiveRunDiagnostics(run);
      const nextSteps = resolvePersistedProductScanSteps(scan, parsedResult.steps);
      const latestActiveStage =
        readOptionalString(activeRunDiagnostics['latestStage']) ??
        readOptionalString(toRecord(resultValue)?.['stage']);
      const manualVerificationPending = shouldKeepAmazonManualVerificationPending({
        parsedStatus: parsedResult.status ?? null,
        existingPending: existingRawResult['manualVerificationPending'] === true,
        latestStage: latestActiveStage,
      });
      const allowManualVerification =
        manualVerificationPending || existingRawResult['allowManualVerification'] === true;
      const runtimePosture = toRecord(activeRunDiagnostics['runtimePosture']);
      const runtimeBrowser = toRecord(runtimePosture?.['browser']);
      const activeRunIsHeadless = runtimeBrowser?.['headless'] === true;
      const shouldRelaunchCaptchaRun =
        parsedResult.status === 'captcha_required' &&
        allowManualVerification &&
        existingRawResult['captchaRetryStarted'] !== true &&
        activeRunIsHeadless;

      if (shouldRelaunchCaptchaRun) {
        if (diagnostics.enabled) {
          await diagnostics.emit('captcha.detected', {
            'raw-engine-result': amazonScanDiagnosticArtifact.json(resultValue),
            'active-run-diagnostics': amazonScanDiagnosticArtifact.json(activeRunDiagnostics),
            'runtime-posture': amazonScanDiagnosticArtifact.json(runtimePosture ?? null),
          });
        }
        return await synchronizeAmazonCaptchaRequired({
          scan,
          run,
          engineRunId,
          resultValue,
          parsedResult,
        });
      }

      const activeMessage =
        manualVerificationPending ? normalizeErrorMessage(parsedResult.message, '') : null;

      const allowedRuntimeMs = resolveAmazonScanRuntimeTimeoutMs({
        allowManualVerification,
        manualVerificationTimeoutMs,
      });
      const staleSyncGraceMs = PRODUCT_SCAN_ORPHANED_ACTIVE_MAX_AGE_MS;
      const activeRunStallThresholdMs = allowedRuntimeMs + staleSyncGraceMs;
      const activeRunAgeMs = resolveIsoAgeMs(run.startedAt) ?? resolveIsoAgeMs(run.createdAt);
      const activeRunIdleAgeMs = resolveIsoAgeMs(run.updatedAt);
      const nextRawResult =
        manualVerificationPending
          ? {
              ...existingRawResult,
              ...activeRunDiagnostics,
              ...resultValue,
              runId: engineRunId,
              runStatus: run.status,
              manualVerificationPending: true,
              manualVerificationMessage: activeMessage,
              manualVerificationTimeoutMs,
            }
          : {
              ...existingRawResult,
              ...activeRunDiagnostics,
              ...resultValue,
              runId: engineRunId,
              runStatus: run.status,
              manualVerificationPending: false,
              manualVerificationMessage: null,
              manualVerificationTimeoutMs,
            };
      const staleActiveReason =
        manualVerificationPending &&
        activeRunAgeMs != null &&
        activeRunAgeMs >= allowedRuntimeMs
          ? 'manual_verification_expired'
          : activeRunIdleAgeMs != null && activeRunIdleAgeMs >= activeRunStallThresholdMs
            ? 'no_progress'
            : activeRunAgeMs != null && activeRunAgeMs >= activeRunStallThresholdMs
              ? 'runtime_exceeded'
              : null;

      if (staleActiveReason) {
        const staleMessage = resolveAmazonActiveRunStallMessage({
          reason: staleActiveReason,
          latestStage:
            readOptionalString((nextRawResult as { latestStage?: unknown })['latestStage']) ??
            readOptionalString((nextRawResult as { stage?: unknown })['stage']),
          runtimeKey: currentAmazonRuntimeKey,
        });
        return await persistSynchronizedScan(scan, {
          engineRunId,
          status: 'failed',
          steps: nextSteps,
          rawResult: {
            ...nextRawResult,
            manualVerificationPending: false,
            manualVerificationMessage: null,
            ...(manualVerificationPending ? { manualVerificationExpired: true } : {}),
            stalledReason: staleActiveReason,
            stalledAt: new Date().toISOString(),
          },
          error: staleMessage,
          asinUpdateStatus: 'failed',
          asinUpdateMessage: staleMessage,
          completedAt: new Date().toISOString(),
        });
      }

      const rawResultChanged =
        JSON.stringify(existingRawResult) !== JSON.stringify(nextRawResult);
      const shouldPersistActiveState =
        scan.status !== run.status ||
        scan.engineRunId !== engineRunId ||
        !areProductScanStepsEqual(scan.steps, nextSteps) ||
        rawResultChanged ||
        (activeMessage ?? null) !== (scan.asinUpdateMessage ?? null) ||
        (manualVerificationPending &&
          existingRawResult['manualVerificationPending'] !== true) ||
        (!manualVerificationPending &&
          (existingRawResult['manualVerificationPending'] === true ||
            readOptionalString(existingRawResult['manualVerificationMessage']) != null));

      if (shouldPersistActiveState) {
        return await persistSynchronizedScan(scan, {
          engineRunId,
          status: run.status,
          steps: nextSteps,
          rawResult: nextRawResult,
          error: null,
          asinUpdateStatus: 'pending',
          asinUpdateMessage: activeMessage,
          completedAt: null,
        });
      }

      return scan;
    }

    if (run.status === 'failed') {
      const failureMessages = collectPlaywrightEngineRunFailureMessages(run);
      const failureMessage = normalizeErrorMessage(
        failureMessages[0],
        `${resolveAmazonRuntimeOperationLabel(currentAmazonRuntimeKey)} failed.`
      );

      return await persistSynchronizedScan(scan, {
        engineRunId,
        status: 'failed',
        steps: resolvePersistedProductScanSteps(scan, parsedResult.steps),
        error: failureMessage,
        rawResult: buildPlaywrightEngineRunFailureMeta(run, { includeRawResult: true }),
        asinUpdateStatus: 'failed',
        asinUpdateMessage: failureMessage,
        completedAt: run.completedAt ?? new Date().toISOString(),
      });
    }

    if (parsedResult.status === 'captcha_required') {
      if (diagnostics.enabled) {
        await diagnostics.emit('captcha.detected', {
          'raw-engine-result': amazonScanDiagnosticArtifact.json(resultValue),
          'parsed-result': amazonScanDiagnosticArtifact.json(parsedResult),
          reason: amazonScanDiagnosticArtifact.text('parsedResult.status === "captcha_required"'),
        });
      }
      return await synchronizeAmazonCaptchaRequired({
        scan,
        run,
        engineRunId,
        resultValue,
        parsedResult,
      });
    }

    if (parsedResult.status === 'triage_ready') {
      if (currentAmazonRuntimeKey === AMAZON_GOOGLE_LENS_CANDIDATE_SEARCH_RUNTIME_KEY) {
        const candidateSelectionMessage =
          parsedResult.message ?? 'Candidates ready for extraction.';
        return await persistSynchronizedScan(scan, {
          engineRunId,
          status: 'completed',
          asin: null,
          matchedImageId: parsedResult.matchedImageId,
          title: null,
          price: null,
          url: resolvePersistableScanUrl(parsedResult.url, parsedResult.currentUrl, finalUrl),
          description: null,
          amazonDetails: null,
          amazonProbe: null,
          amazonEvaluation: null,
          steps: resolvePersistedProductScanSteps(scan, parsedResult.steps),
          rawResult: {
            ...(toRecord(resultValue) ?? {}),
            candidateSelectionRequired: true,
            runtimeKey: currentAmazonRuntimeKey,
            actionId: currentAmazonRuntimeAction?.id ?? null,
          },
          error: null,
          asinUpdateStatus: 'not_needed',
          asinUpdateMessage: candidateSelectionMessage,
          completedAt: run.completedAt ?? new Date().toISOString(),
        });
      }
      if (diagnostics.enabled) {
        await diagnostics.emit('triage.evaluated', {
          'raw-engine-result': amazonScanDiagnosticArtifact.json(resultValue),
          'parsed-result': amazonScanDiagnosticArtifact.json(parsedResult),
          'existing-evaluation': amazonScanDiagnosticArtifact.json(existingAmazonEvaluation),
        });
      }
      return await synchronizeAmazonTriageReady({
        scan,
        run,
        engineRunId,
        resultValue,
        parsedResult,
        persistedAmazonProbe,
        existingAmazonEvaluation,
      });
    }

    if (parsedResult.status === 'probe_ready') {
      if (diagnostics.enabled) {
        await diagnostics.emit('probe.evaluated', {
          'raw-engine-result': amazonScanDiagnosticArtifact.json(resultValue),
          'parsed-result': amazonScanDiagnosticArtifact.json(parsedResult),
          'persisted-probe': amazonScanDiagnosticArtifact.json(persistedAmazonProbe),
          'existing-evaluation': amazonScanDiagnosticArtifact.json(existingAmazonEvaluation),
        });
      }
      return await synchronizeAmazonProbeReady({
        scan,
        run,
        engineRunId,
        resultValue,
        parsedResult,
        persistedAmazonProbe,
        existingAmazonEvaluation,
        finalUrl,
      });
    }

    if (parsedResult.status === 'no_match') {
      if (diagnostics.enabled) {
        await diagnostics.emit('no_match', {
          'raw-engine-result': amazonScanDiagnosticArtifact.json(resultValue),
          'parsed-result': amazonScanDiagnosticArtifact.json(parsedResult),
          'persisted-probe': amazonScanDiagnosticArtifact.json(persistedAmazonProbe),
          'existing-evaluation': amazonScanDiagnosticArtifact.json(existingAmazonEvaluation),
        });
      }
      return await persistSynchronizedScan(scan, {
        engineRunId,
        status: 'no_match',
        matchedImageId: parsedResult.matchedImageId,
        title: parsedResult.title,
        price: parsedResult.price,
        url: resolvePersistableScanUrl(parsedResult.url, parsedResult.currentUrl, finalUrl),
        description: parsedResult.description,
        amazonDetails: parsedResult.amazonDetails,
        amazonProbe: persistedAmazonProbe,
        amazonEvaluation: existingAmazonEvaluation,
        steps: resolvePersistedProductScanSteps(scan, parsedResult.steps),
        rawResult: resultValue,
        error: parsedResult.message,
        asinUpdateStatus: 'not_needed',
        asinUpdateMessage: parsedResult.message,
        completedAt: run.completedAt ?? new Date().toISOString(),
      });
    }

    if (
      parsedResult.status === 'failed' &&
      isGoogleCandidatesNoCandidatesFailure(parsedResult)
    ) {
      const fallbackRetry = await retryAmazonScanWithFallbackProviderAfterNoCandidates({
        scan,
        run,
        engineRunId,
        resultValue,
        parsedResult,
        currentAmazonRuntimeKey,
        currentAmazonRuntimeAction,
        requestedStepSequenceInput,
        persistedAmazonProbe,
        existingAmazonEvaluation,
      });
      if (fallbackRetry) {
        return fallbackRetry;
      }
    }

    if (parsedResult.status === 'failed') {
      const candidateRetry = await retryAmazonScanWithNextCandidateAfterAmazonStageFailure({
        scan,
        run,
        engineRunId,
        resultValue,
        parsedResult,
        currentAmazonRuntimeKey,
        currentAmazonRuntimeAction,
        requestedStepSequenceInput,
        persistedAmazonProbe,
        existingAmazonEvaluation,
        finalUrl,
        diagnosticsEnabled: diagnostics.enabled,
      });
      if (candidateRetry) {
        return candidateRetry;
      }
    }

    if (parsedResult.status !== 'matched') {
      const failureMessage = normalizeErrorMessage(
        parsedResult.message || collectPlaywrightEngineRunFailureMessages(run)[0],
        `${resolveAmazonRuntimeOperationLabel(currentAmazonRuntimeKey)} failed.`
      );
      if (diagnostics.enabled) {
        await diagnostics.emit('failed', {
          'raw-engine-result': amazonScanDiagnosticArtifact.json(resultValue),
          'parsed-result': amazonScanDiagnosticArtifact.json(parsedResult),
          'failure-messages': amazonScanDiagnosticArtifact.json(
            collectPlaywrightEngineRunFailureMessages(run)
          ),
          'failure-message': amazonScanDiagnosticArtifact.text(failureMessage),
        });
      }
      return await persistSynchronizedScan(scan, {
        engineRunId,
        status: 'failed',
        matchedImageId: parsedResult.matchedImageId,
        title: parsedResult.title,
        price: parsedResult.price,
        url: resolvePersistableScanUrl(parsedResult.url, parsedResult.currentUrl, finalUrl),
        description: parsedResult.description,
        amazonDetails: parsedResult.amazonDetails,
        amazonProbe: persistedAmazonProbe,
        amazonEvaluation: existingAmazonEvaluation,
        steps: resolvePersistedProductScanSteps(scan, parsedResult.steps),
        rawResult: resultValue,
        error: failureMessage,
        asinUpdateStatus: 'failed',
        asinUpdateMessage: failureMessage,
        completedAt: run.completedAt ?? new Date().toISOString(),
      });
    }

    if (diagnostics.enabled) {
      await diagnostics.emit('matched', {
        'raw-engine-result': amazonScanDiagnosticArtifact.json(resultValue),
        'parsed-result': amazonScanDiagnosticArtifact.json(parsedResult),
        'persisted-probe': amazonScanDiagnosticArtifact.json(persistedAmazonProbe),
        'existing-evaluation': amazonScanDiagnosticArtifact.json(existingAmazonEvaluation),
      });
    }
    const product = await productService.getProductById(scan.productId);
    if (!product) {
      const message = 'Product not found while finalizing the Amazon scan.';
      const finalizedSteps = upsertPersistedProductScanStep(
        resolvePersistedProductScanSteps(scan, parsedResult.steps),
        {
          key: 'product_asin_update',
          label: 'Update product ASIN',
          group: 'product',
          status: 'failed',
          resultCode: 'product_not_found',
          message,
          details: [{ label: 'Reason', value: 'Product not found' }],
          url: resolvePersistableScanUrl(parsedResult.url, parsedResult.currentUrl, finalUrl),
        }
      );
      return await persistSynchronizedScan(scan, {
        engineRunId,
        status: 'failed',
        asin: parsedResult.asin,
        matchedImageId: parsedResult.matchedImageId,
        title: parsedResult.title,
        price: parsedResult.price,
        url: resolvePersistableScanUrl(parsedResult.url, parsedResult.currentUrl, finalUrl),
        description: parsedResult.description,
        amazonDetails: parsedResult.amazonDetails,
        amazonProbe: persistedAmazonProbe,
        steps: finalizedSteps,
        rawResult: resultValue,
        error: message,
        asinUpdateStatus: 'failed',
        asinUpdateMessage: message,
        completedAt: run.completedAt ?? new Date().toISOString(),
      });
    }

    const resolvedScanUrl = resolvePersistableScanUrl(
      parsedResult.url,
      parsedResult.currentUrl,
      finalUrl
    );
    let finalizedAmazonSteps = resolvePersistedProductScanSteps(scan, parsedResult.steps);
    let amazonEvaluation: ProductScanAmazonEvaluation =
      isApprovedAmazonCandidateExtractionRun(scan) ? existingAmazonEvaluation : null;

    let scannerSettings = createDefaultProductScannerSettings();
    try {
      scannerSettings = (await getProductScannerSettings()) ?? scannerSettings;
    } catch (error) {
      void ErrorSystem.captureException(error, {
        service: 'product-scans.service',
        action: 'synchronizeProductScan.loadScannerSettingsForAmazonEvaluator',
        scanId: scan.id,
        productId: scan.productId,
        engineRunId,
      });
    }

    let extractionEvaluationRawResult: unknown = resultValue;
    try {
      const evaluatorConfig = await resolveAmazonExtractionEvaluatorConfig(scannerSettings);
      if (evaluatorConfig.enabled && !isApprovedAmazonCandidateExtractionRun(scan)) {
      amazonEvaluation = await evaluateProductScanCandidateMatch({
          scan,
          product,
          parsedResult,
          run,
          stage: 'extraction_evaluate',
          evaluatorConfig,
        });
        const latestCandidateMeta = resolveLatestAmazonCandidateStepMeta(finalizedAmazonSteps);

        finalizedAmazonSteps = upsertPersistedProductScanStep(finalizedAmazonSteps, {
          key: 'amazon_ai_evaluate',
          label: 'Evaluate Amazon candidate match',
          group: 'amazon',
          attempt: resolveNextAmazonEvaluationStepAttempt(finalizedAmazonSteps),
          candidateId: latestCandidateMeta.candidateId ?? parsedResult.matchedImageId,
          candidateRank: latestCandidateMeta.candidateRank,
          status: resolveAmazonEvaluationStepStatus(amazonEvaluation),
          resultCode: resolveAmazonEvaluationStepResultCode(amazonEvaluation),
          message: resolveAmazonEvaluationMessage(amazonEvaluation),
          details: buildAmazonEvaluationStepDetails(
            amazonEvaluation,
            evaluatorConfig,
            'extraction'
          ),
          url:
            amazonEvaluation.evidence?.candidateUrl ?? resolvedScanUrl ?? latestCandidateMeta.url,
        });
        extractionEvaluationRawResult = appendAmazonAiStageSummary(
          resultValue,
          buildAmazonEvaluationStageSummary(amazonEvaluation, {
            stage: 'extraction_evaluate',
            candidateRankBefore: latestCandidateMeta.candidateRank,
            provider: resolveAmazonImageSearchProvider(scan.rawResult, scannerSettings),
          })
        );

        if (amazonEvaluation.status === 'failed') {
          const message = resolveAmazonEvaluationMessage(amazonEvaluation);
          return await persistSynchronizedScan(scan, {
            engineRunId,
            status: 'failed',
            asin: null,
            matchedImageId: parsedResult.matchedImageId,
            title: null,
            price: null,
            url: null,
            description: null,
            amazonDetails: null,
            amazonProbe: persistedAmazonProbe,
            amazonEvaluation,
            steps: finalizedAmazonSteps,
            rawResult: extractionEvaluationRawResult,
            error: message,
            asinUpdateStatus: 'failed',
            asinUpdateMessage: message,
            completedAt: run.completedAt ?? new Date().toISOString(),
          });
        }

        if (amazonEvaluation.status === 'rejected') {
          const message = resolveAmazonEvaluationMessage(amazonEvaluation);
          const amazonImageSearchProvider = resolveAmazonImageSearchProvider(
            scan.rawResult,
            scannerSettings
          );
          const amazonImageSearchPageUrl = resolveAmazonImageSearchPageUrl(
            scan.rawResult,
            scannerSettings
          );
          const fallbackProvider =
            amazonEvaluation.recommendedAction === 'fallback_provider'
              ? resolveAmazonImageSearchFallbackProvider({
                  rawResult: scan.rawResult,
                  scannerSettings,
                  currentProvider: amazonImageSearchProvider,
                  imageCandidates: scan.imageCandidates,
                })
              : null;
          if (fallbackProvider) {
            const scannerEngineRequestOptions =
              buildProductScannerEngineRequestOptions(scannerSettings);
            const manualVerificationTimeoutMs =
              resolveScanManualVerificationTimeoutMs(scannerSettings);
            const amazonSelectorProfile =
              readOptionalString(toRecord(scan.rawResult)?.['selectorProfile'], 120) ?? 'amazon';
            const providerHistory = resolveAmazonImageSearchProviderHistory(
              scan.rawResult,
              amazonImageSearchProvider
            );
            const fallbackRuntimeKey =
              currentAmazonRuntimeKey === AMAZON_CANDIDATE_EXTRACTION_RUNTIME_KEY
                ? AMAZON_REVERSE_IMAGE_SCAN_RUNTIME_KEY
                : currentAmazonRuntimeKey;
            const fallbackRuntimeAction = await resolveAmazonRuntimeActionDefinition(
              fallbackRuntimeKey
            );
            const fallbackScannerRuntimeOptions = buildAmazonScannerRequestRuntimeOptions({
              scannerSettings,
              scannerEngineRequestOptions,
              actionExecutionSettings: fallbackRuntimeAction?.executionSettings ?? null,
              actionPersonaId: fallbackRuntimeAction?.personaId ?? null,
              runtimeKey: fallbackRuntimeKey,
            });
            const fallbackRun = await startPlaywrightEngineTask({
              request: {
                runtimeKey: fallbackRuntimeKey,
                actionId: fallbackRuntimeAction?.id ?? null,
                actionName:
                  fallbackRuntimeAction?.name ??
                  resolveAmazonRuntimeActionName(fallbackRuntimeKey),
                selectorProfile: amazonSelectorProfile,
                input: amazonScanRuntime.buildRequestInput({
                  productId: product.id,
                  productName: scan.productName,
                  existingAsin: product.asin,
                  imageCandidates: scan.imageCandidates,
                  runtimeKey: fallbackRuntimeKey,
                  imageSearchProvider: fallbackProvider,
                  imageSearchPageUrl: amazonImageSearchPageUrl,
                  selectorProfile: amazonSelectorProfile,
                  allowManualVerification:
                    shouldAutoShowScannerCaptchaBrowser(scannerSettings),
                  manualVerificationTimeoutMs,
                  triageOnlyOnAmazonCandidates:
                    (await resolveAmazonTriageEvaluatorConfig(scannerSettings)).enabled,
                  probeOnlyOnAmazonMatch:
                    (await resolveAmazonProbeEvaluatorConfig(scannerSettings)).enabled,
                  ...requestedStepSequenceInput,
                }),
                timeoutMs: resolveAmazonScanRuntimeTimeoutMs({
                  allowManualVerification: shouldAutoShowScannerCaptchaBrowser(scannerSettings),
                  manualVerificationTimeoutMs,
                }),
                browserEngine: 'chromium',
                ...fallbackScannerRuntimeOptions,
                capture: resolveAmazonScanDiagnosticCapture(scan.rawResult),
                preventNewPages: true,
              },
              ownerUserId: scan.updatedBy?.trim() || null,
              instance: createCustomPlaywrightInstance({
                family: 'scrape',
                label: 'Amazon fallback provider scan',
                tags: ['product', 'amazon', 'scan', 'provider-fallback'],
              }),
            });

            const fallbackStatus = fallbackRun.status === 'running' ? 'running' : 'queued';
            return await persistSynchronizedScan(scan, {
              engineRunId: fallbackRun.runId,
              status: fallbackStatus,
              asin: null,
              matchedImageId: parsedResult.matchedImageId,
              title: null,
              price: null,
              url: null,
              description: null,
              amazonDetails: null,
              amazonProbe: persistedAmazonProbe,
              amazonEvaluation,
              steps: upsertPersistedProductScanStep(finalizedAmazonSteps, {
                key: 'queue_scan',
                label: 'Retry with fallback image-search provider',
                group: 'input',
                attempt: resolveNextQueueStepAttempt(finalizedAmazonSteps),
                status: 'completed',
                resultCode: fallbackStatus === 'running' ? 'run_started' : 'run_queued',
                message:
                  fallbackStatus === 'running'
                    ? 'Started an Amazon scan with the fallback image-search provider.'
                    : 'Queued an Amazon scan with the fallback image-search provider.',
                details: [
                  { label: 'Previous provider', value: amazonImageSearchProvider },
                  { label: 'Fallback provider', value: fallbackProvider },
                  { label: 'Rejection category', value: amazonEvaluation.rejectionCategory },
                ],
                url: null,
              }),
              rawResult: appendAmazonAiStageSummary(
                {
                  ...createProductScanStartedRawResult({
                    runId: fallbackRun.runId,
                    status: fallbackRun.status,
                    runtimeKey: fallbackRuntimeKey,
                    actionId: fallbackRuntimeAction?.id ?? null,
                    selectorProfile: amazonSelectorProfile,
                    imageSearchProvider: fallbackProvider,
                    imageSearchPageUrl: amazonImageSearchPageUrl,
                    imageSearchProviderHistory: [...providerHistory, fallbackProvider],
                    allowManualVerification:
                      shouldAutoShowScannerCaptchaBrowser(scannerSettings),
                    manualVerificationTimeoutMs,
                    previousRunId: engineRunId,
                    previousResult: extractionEvaluationRawResult,
                    recordDiagnostics: diagnostics.enabled,
                    ...requestedStepSequenceInput,
                  }),
                  providerFallback: true,
                  fallbackFromImageSearchProvider: amazonImageSearchProvider,
                  fallbackToImageSearchProvider: fallbackProvider,
                },
                buildAmazonEvaluationStageSummary(amazonEvaluation, {
                  stage: 'extraction_evaluate',
                  candidateRankBefore: latestCandidateMeta.candidateRank,
                  provider: amazonImageSearchProvider,
                })
              ),
              error: null,
              asinUpdateStatus: 'pending',
              asinUpdateMessage: null,
              completedAt: null,
            });
          }
          const nextCandidate = resolveNextAmazonCandidateUrl({
            candidateUrls: parsedResult.candidateUrls,
            currentUrl: resolvedScanUrl,
          });
          if (
            amazonEvaluation.recommendedAction === 'try_next_candidate' &&
            nextCandidate.nextUrl &&
            nextCandidate.nextRank
          ) {
            const scannerEngineRequestOptions =
              buildProductScannerEngineRequestOptions(scannerSettings);
            const scannerRuntimeOptions = buildAmazonScannerRequestRuntimeOptions({
              scannerSettings,
              scannerEngineRequestOptions,
              actionExecutionSettings: currentAmazonRuntimeAction?.executionSettings ?? null,
              actionPersonaId: currentAmazonRuntimeAction?.personaId ?? null,
              runtimeKey: currentAmazonRuntimeKey,
            });
            const manualVerificationTimeoutMs =
              resolveScanManualVerificationTimeoutMs(scannerSettings);
            const amazonSelectorProfile =
              readOptionalString(toRecord(scan.rawResult)?.['selectorProfile'], 120) ?? 'amazon';
            const continuationRun = await startPlaywrightEngineTask({
              request: {
                runtimeKey: currentAmazonRuntimeKey,
                actionId: currentAmazonRuntimeAction?.id ?? null,
                actionName:
                  currentAmazonRuntimeAction?.name ??
                  resolveAmazonRuntimeActionName(currentAmazonRuntimeKey),
                selectorProfile: amazonSelectorProfile,
                input: amazonScanRuntime.buildRequestInput({
                  productId: product.id,
                  productName: scan.productName,
                  existingAsin: product.asin,
                  imageCandidates: scan.imageCandidates,
                  runtimeKey: currentAmazonRuntimeKey,
                  imageSearchProvider: amazonImageSearchProvider,
                  imageSearchPageUrl: amazonImageSearchPageUrl,
                  selectorProfile: amazonSelectorProfile,
                  allowManualVerification:
                    shouldAutoShowScannerCaptchaBrowser(scannerSettings),
                  manualVerificationTimeoutMs,
                  probeOnlyOnAmazonMatch: true,
                  skipAmazonProbe: false,
                  directAmazonCandidateUrl: nextCandidate.nextUrl,
                  directAmazonCandidateUrls: nextCandidate.remainingCandidateUrls,
                  directMatchedImageId: parsedResult.matchedImageId,
                  directAmazonCandidateRank: nextCandidate.nextRank,
                  ...requestedStepSequenceInput,
                }),
                timeoutMs: resolveAmazonScanRuntimeTimeoutMs({
                  allowManualVerification: shouldAutoShowScannerCaptchaBrowser(scannerSettings),
                  manualVerificationTimeoutMs,
                }),
                browserEngine: 'chromium',
                ...scannerRuntimeOptions,
                capture: resolveAmazonScanDiagnosticCapture(scan.rawResult),
                preventNewPages: true,
              },
              ownerUserId: scan.updatedBy?.trim() || null,
              instance: createCustomPlaywrightInstance({
                family: 'scrape',
                label: 'Amazon candidate continuation scan',
                tags: ['product', 'amazon', 'scan', 'candidate-continuation'],
              }),
            });

            const continuationStatus =
              continuationRun.status === 'running' ? 'running' : 'queued';
            return await persistSynchronizedScan(scan, {
              engineRunId: continuationRun.runId,
              status: continuationStatus,
              asin: null,
              matchedImageId: parsedResult.matchedImageId,
              title: null,
              price: null,
              url: nextCandidate.nextUrl,
              description: null,
              amazonDetails: null,
              amazonProbe: persistedAmazonProbe,
              amazonEvaluation,
              steps: upsertPersistedProductScanStep(finalizedAmazonSteps, {
                key: 'queue_scan',
                label: 'Continue with next Amazon candidate',
                group: 'input',
                attempt: resolveNextQueueStepAttempt(finalizedAmazonSteps),
                status: 'completed',
                resultCode: continuationStatus === 'running' ? 'run_started' : 'run_queued',
                message:
                  continuationStatus === 'running'
                    ? 'Started the next Amazon candidate after extraction-stage AI rejection.'
                    : 'Queued the next Amazon candidate after extraction-stage AI rejection.',
                details: [
                  { label: 'Rejection category', value: amazonEvaluation.rejectionCategory },
                  { label: 'Rejected candidate URL', value: resolvedScanUrl },
                  { label: 'Next candidate URL', value: nextCandidate.nextUrl },
                ],
                url: nextCandidate.nextUrl,
              }),
              rawResult: appendAmazonAiStageSummary(
                {
                  ...createProductScanStartedRawResult({
                    runId: continuationRun.runId,
                    status: continuationRun.status,
                    runtimeKey: currentAmazonRuntimeKey,
                    actionId: currentAmazonRuntimeAction?.id ?? null,
                    selectorProfile: amazonSelectorProfile,
                    imageSearchProvider: amazonImageSearchProvider,
                    imageSearchPageUrl: amazonImageSearchPageUrl,
                    imageSearchProviderHistory: resolveAmazonImageSearchProviderHistory(
                      scan.rawResult,
                      amazonImageSearchProvider
                    ),
                    allowManualVerification:
                      shouldAutoShowScannerCaptchaBrowser(scannerSettings),
                    manualVerificationTimeoutMs,
                    previousRunId: engineRunId,
                    previousResult: extractionEvaluationRawResult,
                    recordDiagnostics: diagnostics.enabled,
                    ...requestedStepSequenceInput,
                  }),
                  candidateRejectedByAi: true,
                  candidateContinuation: true,
                  approvedCandidateExtraction: false,
                  continuationCandidateUrls: nextCandidate.remainingCandidateUrls,
                },
                buildAmazonEvaluationStageSummary(amazonEvaluation, {
                  stage: 'extraction_evaluate',
                  candidateRankBefore: latestCandidateMeta.candidateRank,
                  provider: amazonImageSearchProvider,
                })
              ),
              error: null,
              asinUpdateStatus: 'pending',
              asinUpdateMessage: null,
              completedAt: null,
            });
          }
          const skippedUpdateSteps = upsertPersistedProductScanStep(finalizedAmazonSteps, {
            key: 'product_asin_update',
            label: 'Update product ASIN',
            group: 'product',
            status: 'skipped',
            resultCode: 'asin_not_needed',
            message:
              'Skipped product ASIN update because the AI evaluator rejected the Amazon candidate.',
            details: [{ label: 'Reason', value: message }],
            url: amazonEvaluation.evidence?.candidateUrl ?? resolvedScanUrl,
          });
          return await persistSynchronizedScan(scan, {
            engineRunId,
            status: 'no_match',
            asin:
              amazonEvaluation.rejectionCategory === 'language' &&
              amazonEvaluation.sameProduct === true
                ? parsedResult.asin
                : null,
            matchedImageId: parsedResult.matchedImageId,
            title: null,
            price: null,
            url:
              amazonEvaluation.rejectionCategory === 'language' &&
              amazonEvaluation.sameProduct === true
                ? resolvedScanUrl
                : null,
            description: null,
            amazonDetails:
              amazonEvaluation.rejectionCategory === 'language' &&
              amazonEvaluation.sameProduct === true
                ? parsedResult.amazonDetails
                : null,
            amazonProbe: persistedAmazonProbe,
            amazonEvaluation,
            steps: skippedUpdateSteps,
            rawResult: extractionEvaluationRawResult,
            error: message,
            asinUpdateStatus: 'not_needed',
            asinUpdateMessage: message,
            completedAt: run.completedAt ?? new Date().toISOString(),
          });
        }
      }
    } catch (error) {
      const message = normalizeErrorMessage(
        error instanceof Error ? error.message : error,
        'Amazon candidate AI evaluation failed.'
      );
      const latestCandidateMeta = resolveLatestAmazonCandidateStepMeta(finalizedAmazonSteps);
      amazonEvaluation = {
        stage: 'extraction_evaluate',
        status: 'failed',
        sameProduct: null,
        imageMatch: null,
        descriptionMatch: null,
        pageRepresentsSameProduct: null,
        confidence: null,
        proceed: false,
        scrapeAllowed: false,
        recommendedAction: null,
        rejectionCategory: null,
        threshold: null,
        reasons: [],
        mismatches: [],
        mismatchLabels: [],
        variantAssessment: null,
        modelId: null,
        brainApplied: null,
        evidence: {
          candidateUrl: resolvedScanUrl,
          pageTitle: parsedResult.title,
          heroImageSource: null,
          heroImageArtifactName: null,
          screenshotArtifactName: null,
          htmlArtifactName: null,
          productImageSource:
            scan.imageCandidates[0]?.url ?? scan.imageCandidates[0]?.filepath ?? null,
        },
        error: message,
        evaluatedAt: new Date().toISOString(),
      };
      const evaluationCandidateUrl =
        amazonEvaluation.evidence?.candidateUrl ?? resolvedScanUrl ?? latestCandidateMeta.url;
      finalizedAmazonSteps = upsertPersistedProductScanStep(finalizedAmazonSteps, {
        key: 'amazon_ai_evaluate',
        label: 'Evaluate Amazon candidate match',
        group: 'amazon',
        attempt: resolveNextAmazonEvaluationStepAttempt(finalizedAmazonSteps),
        candidateId: latestCandidateMeta.candidateId ?? parsedResult.matchedImageId,
        candidateRank: latestCandidateMeta.candidateRank,
        status: 'failed',
        resultCode: 'evaluation_failed',
        message,
        details: [
          { label: 'Candidate URL', value: evaluationCandidateUrl },
          { label: 'Error', value: message },
        ],
        url: evaluationCandidateUrl,
      });
      return await persistSynchronizedScan(scan, {
        engineRunId,
        status: 'failed',
        asin: null,
        matchedImageId: parsedResult.matchedImageId,
        title: null,
        price: null,
        url: null,
        description: null,
        amazonDetails: null,
        amazonProbe: persistedAmazonProbe,
        amazonEvaluation,
        steps: finalizedAmazonSteps,
        rawResult: resultValue,
        error: message,
        asinUpdateStatus: 'failed',
        asinUpdateMessage: message,
        completedAt: run.completedAt ?? new Date().toISOString(),
      });
    }

    const asinOutcome = resolveDetectedAmazonAsinOutcome({
      existingAsin: product.asin,
      detectedAsin: parsedResult.asin,
    });

    let updateFailureMessage: string | null = null;
    if (asinOutcome.asinUpdateStatus === 'updated' && asinOutcome.normalizedDetectedAsin) {
      try {
        await productService.updateProduct(
          product.id,
          { asin: asinOutcome.normalizedDetectedAsin },
          scan.updatedBy ? { userId: scan.updatedBy } : undefined
        );
        CachedProductService.invalidateProduct(product.id);
      } catch (error) {
        updateFailureMessage = normalizeErrorMessage(
          error instanceof Error ? error.message : error,
          'Failed to update product ASIN.'
        );
      }
    }

    const nextStatus = updateFailureMessage ? 'failed' : asinOutcome.scanStatus;
    const nextAsinUpdateStatus = updateFailureMessage ? 'failed' : asinOutcome.asinUpdateStatus;
    const nextMessage = updateFailureMessage ?? asinOutcome.message;
    const writeEnglishFields = shouldWriteAmazonEnglishContent(amazonEvaluation);
    const finalizedSteps = upsertPersistedProductScanStep(finalizedAmazonSteps, {
      key: 'product_asin_update',
      label: 'Update product ASIN',
      group: 'product',
      status: resolveAsinUpdateStepStatus(nextAsinUpdateStatus),
      resultCode:
        nextAsinUpdateStatus === 'updated'
          ? 'asin_updated'
          : nextAsinUpdateStatus === 'unchanged'
            ? 'asin_unchanged'
            : nextAsinUpdateStatus === 'conflict'
              ? 'asin_conflict'
              : nextAsinUpdateStatus === 'not_needed'
                ? 'asin_not_needed'
                : 'asin_update_failed',
      message: nextMessage,
      details: [
        { label: 'Detected ASIN', value: asinOutcome.normalizedDetectedAsin },
        { label: 'Existing ASIN', value: product.asin ?? null },
      ],
      url: resolvePersistableScanUrl(parsedResult.url, parsedResult.currentUrl, finalUrl),
    });

    return await persistSynchronizedScan(scan, {
      engineRunId,
      status: nextStatus,
      asin: asinOutcome.normalizedDetectedAsin,
      matchedImageId: parsedResult.matchedImageId,
      title: writeEnglishFields ? parsedResult.title : null,
      price: parsedResult.price,
      url: resolvedScanUrl,
      description: writeEnglishFields ? parsedResult.description : null,
      amazonDetails: parsedResult.amazonDetails,
      amazonProbe: persistedAmazonProbe,
      amazonEvaluation,
      steps: finalizedSteps,
      rawResult: extractionEvaluationRawResult,
      error: nextStatus === 'failed' || nextStatus === 'conflict' ? nextMessage : null,
      asinUpdateStatus: nextAsinUpdateStatus,
      asinUpdateMessage: nextMessage,
      completedAt: run.completedAt ?? new Date().toISOString(),
    });
  } catch (error) {
    const message =
      error instanceof Error
        ? error.message
        : `Failed to synchronize ${resolveAmazonRuntimeOperationLabel(resolveAmazonScanRuntimeKey(scan))}.`;
    return await persistFailedSynchronization(scan, message);
  }
}

import 'server-only';

import type { ScripterImportDraft } from '@/features/playwright/scripters';
import type { ProductScrapeProfileRunProduct } from '@/shared/contracts/products/scrape-profiles';
import type { CatalogRecord } from '@/shared/contracts/products/catalogs';
import type { ProductWithImages } from '@/shared/contracts/products/product';
import type { ProductCreateInput, ProductUpdateInput } from '@/shared/contracts/products/io';
import type { ProductDraft } from '@/shared/contracts/products/drafts';
import { productService } from '@/shared/lib/products/services/productService';
import {
  buildCandidate,
  buildCandidateDuplicateKeys,
  type ProductScrapeCandidate,
  type ProductScrapeProfileConfig,
} from './product-scrape-profiles.candidates';
import {
  type ScrapeTemplateValues,
  buildScrapeTemplateValues,
  renderScrapeTemplateCustomFields,
  renderScrapeTemplateMarketplaceOverrides,
  renderScrapeTemplateNotes,
  renderScrapeTemplateParameterValues,
  renderScrapeTemplateText,
} from './product-scrape-template-renderer';

export type { ProductScrapeProfileConfig } from './product-scrape-profiles.candidates';

type ProductScrapeDuplicateState = {
  seenKeys: Set<string>;
};
type ProductScrapeDraftOutcome = {
  result: ProductScrapeProfileRunProduct;
  createdCount: number;
  updatedCount: number;
  skippedCount: number;
  failedCount: number;
};
type ProductScrapeOutcomeSummary = {
  createdCount: number;
  updatedCount: number;
  skippedCount: number;
  failedCount: number;
  products: ProductScrapeProfileRunProduct[];
};
type ProductScrapeRunContext = {
  profile: ProductScrapeProfileConfig;
  catalog: CatalogRecord;
  dryRun: boolean;
  skipRecordsWithErrors: boolean;
  productServiceOptions: { userId?: string } | undefined;
  duplicateState?: ProductScrapeDuplicateState;
  draftTemplate?: ProductDraft | null;
};

const normalizeString = (value: unknown): string | null => {
  if (typeof value !== 'string') return null;
  const trimmed = value.trim();
  return trimmed.length > 0 ? trimmed : null;
};

const hasBlockingIssue = (draft: ScripterImportDraft): boolean =>
  draft.issues.some((issue) => issue.severity === 'error');

const formatDraftIssues = (draft: ScripterImportDraft): string =>
  draft.issues
    .map((issue) => `${issue.field}: ${issue.message}`)
    .filter((message) => message.trim().length > 0)
    .join('; ');

const existingCatalogIds = (product: ProductWithImages | null, catalogId: string): string[] => {
  const ids = new Set<string>();
  if (product !== null) {
    product.catalogs.forEach((relation) => {
      if (relation.catalogId.trim().length > 0) ids.add(relation.catalogId);
    });
  }
  ids.add(catalogId);
  return Array.from(ids);
};

const mergeTemplateCatalogIds = (
  catalogIds: string[],
  template: ProductDraft | null | undefined
): string[] => {
  const ids = new Set(catalogIds);
  (template?.catalogIds ?? []).forEach((catalogId) => {
    if (catalogId.trim().length > 0) ids.add(catalogId);
  });
  return Array.from(ids);
};

const markDuplicateCandidate = (
  candidate: ProductScrapeCandidate,
  context: ProductScrapeRunContext
): boolean => {
  const state = context.duplicateState;
  if (state === undefined) return false;
  const keys = buildCandidateDuplicateKeys(candidate, context.profile);
  if (keys.some((key) => state.seenKeys.has(key))) return true;
  keys.forEach((key) => state.seenKeys.add(key));
  return false;
};

const hasTemplateNumber = (value: number | null | undefined): value is number =>
  typeof value === 'number' && Number.isFinite(value);

const hasTemplateString = (value: string | null | undefined): value is string =>
  typeof value === 'string' && value.trim().length > 0;

const buildTemplatePayloadDefaults = (
  template: ProductDraft | null | undefined,
  values: ScrapeTemplateValues
): Partial<ProductCreateInput & ProductUpdateInput> => {
  if (template === null || template === undefined) return {};
  const ean = renderScrapeTemplateText(template.ean, values);
  const gtin = renderScrapeTemplateText(template.gtin, values);
  const asin = renderScrapeTemplateText(template.asin, values);
  const customFields = renderScrapeTemplateCustomFields(template.customFields, values);
  const marketplaceContentOverrides = renderScrapeTemplateMarketplaceOverrides(
    template.marketplaceContentOverrides,
    values
  );
  const notes = renderScrapeTemplateNotes(template.notes, values);

  return {
    ...(ean !== null ? { ean } : {}),
    ...(gtin !== null ? { gtin } : {}),
    ...(asin !== null ? { asin } : {}),
    ...(hasTemplateNumber(template.price) ? { price: template.price } : {}),
    ...(hasTemplateNumber(template.weight) ? { weight: template.weight } : {}),
    ...(hasTemplateNumber(template.sizeLength) ? { sizeLength: template.sizeLength } : {}),
    ...(hasTemplateNumber(template.sizeWidth) ? { sizeWidth: template.sizeWidth } : {}),
    ...(hasTemplateNumber(template.length) ? { length: template.length } : {}),
    ...(hasTemplateNumber(template.stock) ? { stock: template.stock } : {}),
    ...(hasTemplateString(template.defaultPriceGroupId)
      ? { defaultPriceGroupId: template.defaultPriceGroupId }
      : {}),
    ...(hasTemplateString(template.shippingGroupId)
      ? { shippingGroupId: template.shippingGroupId }
      : {}),
    ...(customFields.length > 0 ? { customFields } : {}),
    ...(marketplaceContentOverrides.length > 0 ? { marketplaceContentOverrides } : {}),
    ...(notes !== null ? { notes } : {}),
  };
};

const buildCreatePayload = (
  candidate: ProductScrapeCandidate,
  draft: ScripterImportDraft,
  profile: ProductScrapeProfileConfig,
  catalogIds: string[],
  template?: ProductDraft | null
): ProductCreateInput => {
  const values = buildScrapeTemplateValues(draft, candidate);
  const nameEn = renderScrapeTemplateText(template?.name_en, values);
  const nameDe = renderScrapeTemplateText(template?.name_de, values);
  const descriptionEn = renderScrapeTemplateText(template?.description_en, values);
  const descriptionPl = renderScrapeTemplateText(template?.description_pl, values);
  const descriptionDe = renderScrapeTemplateText(template?.description_de, values);
  const templateDefaults = buildTemplatePayloadDefaults(template, values);
  return {
    sku: renderScrapeTemplateText(template?.sku, values) ?? candidate.sku,
    importSource: 'scrape',
    ...(nameEn !== null ? { name_en: nameEn } : {}),
    name_pl: renderScrapeTemplateText(template?.name_pl, values) ?? candidate.title,
    ...(nameDe !== null ? { name_de: nameDe } : {}),
    ...(descriptionEn !== null ? { description_en: descriptionEn } : {}),
    ...(descriptionPl !== null ? { description_pl: descriptionPl } : {}),
    ...(descriptionDe !== null ? { description_de: descriptionDe } : {}),
    supplierName: renderScrapeTemplateText(template?.supplierName, values) ?? profile.supplierName,
    supplierLink: renderScrapeTemplateText(template?.supplierLink, values) ?? candidate.sourceUrl,
    priceComment: renderScrapeTemplateText(template?.priceComment, values) ?? profile.priceComment,
    ...templateDefaults,
    stock: templateDefaults.stock ?? 0,
    catalogIds,
    ...(template?.categoryId ? { categoryId: template.categoryId } : {}),
    ...(template?.tagIds && template.tagIds.length > 0 ? { tagIds: template.tagIds } : {}),
    ...(template?.producerIds && template.producerIds.length > 0
      ? { producerIds: template.producerIds }
      : {}),
    ...(template?.parameters && template.parameters.length > 0
      ? { parameters: renderScrapeTemplateParameterValues(template.parameters, values) }
      : {}),
    imageLinks: candidate.imageLinks,
    ...(candidate.price !== null ? { sourcePrice: candidate.price } : {}),
  };
};

const buildUpdatePayload = (
  candidate: ProductScrapeCandidate,
  draft: ScripterImportDraft,
  profile: ProductScrapeProfileConfig,
  catalogIds: string[],
  template?: ProductDraft | null
): ProductUpdateInput => {
  const values = buildScrapeTemplateValues(draft, candidate);
  const nameEn = renderScrapeTemplateText(template?.name_en, values);
  const nameDe = renderScrapeTemplateText(template?.name_de, values);
  const descriptionEn = renderScrapeTemplateText(template?.description_en, values);
  const descriptionPl = renderScrapeTemplateText(template?.description_pl, values);
  const descriptionDe = renderScrapeTemplateText(template?.description_de, values);
  const templateDefaults = buildTemplatePayloadDefaults(template, values);
  return {
    sku: renderScrapeTemplateText(template?.sku, values) ?? candidate.sku,
    importSource: 'scrape',
    ...(nameEn !== null ? { name_en: nameEn } : {}),
    name_pl: renderScrapeTemplateText(template?.name_pl, values) ?? candidate.title,
    ...(nameDe !== null ? { name_de: nameDe } : {}),
    ...(descriptionEn !== null ? { description_en: descriptionEn } : {}),
    ...(descriptionPl !== null ? { description_pl: descriptionPl } : {}),
    ...(descriptionDe !== null ? { description_de: descriptionDe } : {}),
    supplierName: renderScrapeTemplateText(template?.supplierName, values) ?? profile.supplierName,
    supplierLink: renderScrapeTemplateText(template?.supplierLink, values) ?? candidate.sourceUrl,
    priceComment: renderScrapeTemplateText(template?.priceComment, values) ?? profile.priceComment,
    ...templateDefaults,
    catalogIds,
    ...(template?.categoryId ? { categoryId: template.categoryId } : {}),
    ...(template?.tagIds && template.tagIds.length > 0 ? { tagIds: template.tagIds } : {}),
    ...(template?.producerIds && template.producerIds.length > 0
      ? { producerIds: template.producerIds }
      : {}),
    ...(template?.parameters && template.parameters.length > 0
      ? { parameters: renderScrapeTemplateParameterValues(template.parameters, values) }
      : {}),
    imageLinks: candidate.imageLinks,
    ...(candidate.price !== null ? { sourcePrice: candidate.price } : {}),
  };
};

const resolveResultPayloadTitle = (
  payload: ProductCreateInput | ProductUpdateInput,
  candidate: ProductScrapeCandidate
): string =>
  payload.name_pl ??
  payload.name_en ??
  payload.name_de ??
  candidate.title;

const resolveResultTitle = (
  draft: ScripterImportDraft,
  candidate: ProductScrapeCandidate | null
): string | null => candidate?.title ?? normalizeString(draft.draft.name) ?? null;

const resolveResultSourceUrl = (
  draft: ScripterImportDraft,
  candidate: ProductScrapeCandidate | null
): string | null => candidate?.sourceUrl ?? normalizeString(draft.draft.supplierLink) ?? null;

const toResultProduct = (
  draft: ScripterImportDraft,
  candidate: ProductScrapeCandidate | null,
  status: ProductScrapeProfileRunProduct['status'],
  options?: { productId?: string | null; error?: string | null; title?: string | null }
): ProductScrapeProfileRunProduct => ({
  index: draft.index,
  status,
  productId: options?.productId ?? null,
  sku: candidate?.sku ?? null,
  title: options?.title ?? resolveResultTitle(draft, candidate),
  sourceUrl: resolveResultSourceUrl(draft, candidate),
  error: options?.error ?? null,
});

const createOutcome = (
  result: ProductScrapeProfileRunProduct,
  counts: Partial<Omit<ProductScrapeDraftOutcome, 'result'>> = {}
): ProductScrapeDraftOutcome => ({
  result,
  createdCount: counts.createdCount ?? 0,
  updatedCount: counts.updatedCount ?? 0,
  skippedCount: counts.skippedCount ?? 0,
  failedCount: counts.failedCount ?? 0,
});

const processPersistedCandidate = async (
  draft: ScripterImportDraft,
  candidate: ProductScrapeCandidate,
  context: ProductScrapeRunContext
): Promise<ProductScrapeDraftOutcome> => {
  const existingBySku = await productService.getProductBySku(candidate.sku);
  const existing =
    existingBySku ?? (await productService.findProductBySupplierLink(candidate.sourceUrl));
  const catalogIds = mergeTemplateCatalogIds(
    existingCatalogIds(existing, context.catalog.id),
    context.draftTemplate
  );
  if (existing !== null) {
    const payload = buildUpdatePayload(
      candidate,
      draft,
      context.profile,
      catalogIds,
      context.draftTemplate
    );
    const updated = await productService.updateProduct(
      existing.id,
      payload,
      context.productServiceOptions
    );
    return createOutcome(
      toResultProduct(draft, candidate, 'updated', {
        productId: updated.id,
        title: resolveResultPayloadTitle(payload, candidate),
      }),
      { updatedCount: 1 }
    );
  }
  const payload = buildCreatePayload(
    candidate,
    draft,
    context.profile,
    mergeTemplateCatalogIds([context.catalog.id], context.draftTemplate),
    context.draftTemplate
  );
  const created = await productService.createProduct(
    payload,
    context.productServiceOptions
  );
  return createOutcome(
    toResultProduct(draft, candidate, 'created', {
      productId: created.id,
      title: resolveResultPayloadTitle(payload, candidate),
    }),
    { createdCount: 1 }
  );
};

const processValidScrapeCandidate = async (
  draft: ScripterImportDraft,
  candidate: ProductScrapeCandidate,
  context: ProductScrapeRunContext
): Promise<ProductScrapeDraftOutcome> => {
  if (markDuplicateCandidate(candidate, context)) {
    return createOutcome(
      toResultProduct(draft, candidate, 'skipped', {
        error: 'Duplicate scraped product in this run.',
      }),
      { skippedCount: 1 }
    );
  }
  if (context.dryRun) {
    const payload = buildCreatePayload(
      candidate,
      draft,
      context.profile,
      mergeTemplateCatalogIds([context.catalog.id], context.draftTemplate),
      context.draftTemplate
    );
    return createOutcome(
      toResultProduct(draft, candidate, 'dry_run', {
        title: resolveResultPayloadTitle(payload, candidate),
      })
    );
  }
  try {
    return await processPersistedCandidate(draft, candidate, context);
  } catch (error) {
    return createOutcome(
      toResultProduct(draft, candidate, 'failed', {
        error: error instanceof Error ? error.message : String(error),
      }),
      { failedCount: 1 }
    );
  }
};

export const processScrapeDraft = async (
  draft: ScripterImportDraft,
  context: ProductScrapeRunContext
): Promise<ProductScrapeDraftOutcome> => {
  const candidate = buildCandidate(draft, context.profile);
  if (hasBlockingIssue(draft) && context.skipRecordsWithErrors) {
    const issueText = formatDraftIssues(draft);
    return createOutcome(
      toResultProduct(draft, candidate, 'skipped', {
        error: issueText.length > 0 ? issueText : 'Record has blocking mapping errors.',
      }),
      { skippedCount: 1 }
    );
  }
  if (candidate === null) {
    return createOutcome(
      toResultProduct(draft, candidate, 'failed', {
        error: 'Product title, SKU source, or source URL could not be resolved.',
      }),
      { failedCount: 1 }
    );
  }
  return await processValidScrapeCandidate(draft, candidate, context);
};

export const processScrapeDrafts = async (
  drafts: ScripterImportDraft[],
  context: ProductScrapeRunContext
): Promise<ProductScrapeDraftOutcome[]> => {
  const runContext: ProductScrapeRunContext = {
    ...context,
    duplicateState: context.duplicateState ?? { seenKeys: new Set<string>() },
  };
  return await drafts.reduce<Promise<ProductScrapeDraftOutcome[]>>(async (previous, draft) => {
    const outcomes = await previous;
    outcomes.push(await processScrapeDraft(draft, runContext));
    return outcomes;
  }, Promise.resolve([]));
};
export const summarizeOutcomes = (
  outcomes: ProductScrapeDraftOutcome[]
): ProductScrapeOutcomeSummary =>
  outcomes.reduce(
    (summary, outcome) => ({
      createdCount: summary.createdCount + outcome.createdCount,
      updatedCount: summary.updatedCount + outcome.updatedCount,
      skippedCount: summary.skippedCount + outcome.skippedCount,
      failedCount: summary.failedCount + outcome.failedCount,
      products: [...summary.products, outcome.result],
    }),
    {
      createdCount: 0,
      updatedCount: 0,
      skippedCount: 0,
      failedCount: 0,
      products: [] as ProductScrapeProfileRunProduct[],
    }
  );

import type { ScripterImportDraft } from '@/features/playwright/scripters';
import type { MappedScripterRecord } from '@/features/playwright/scripters/types';
import type { ProductCustomFieldValue } from '@/shared/contracts/products/custom-fields';
import type { ProductDraft } from '@/shared/contracts/products/drafts';
import type {
  ProductMarketplaceContentOverrideDraft,
  ProductNotes,
  ProductParameterValue,
} from '@/shared/contracts/products/product';
export { SCRAPE_TEMPLATE_PLACEHOLDER_OPTIONS } from '@/shared/contracts/products/scrape-template-placeholders';
export type { ScrapeTemplatePlaceholderOption } from '@/shared/contracts/products/scrape-template-placeholders';

import type { ProductScrapeCandidate } from './product-scrape-profiles.candidates';

type PlaceholderValue = string | number | null | undefined;
export type ScrapeTemplateValues = Record<string, PlaceholderValue>;

const PLACEHOLDER_PATTERN = /\[([a-zA-Z][a-zA-Z0-9_.-]*)\]/g;

const normalizeTemplateString = (value: unknown): string | null => {
  if (typeof value !== 'string') return null;
  const trimmed = value.trim();
  return trimmed.length > 0 ? trimmed : null;
};

const valueToString = (value: PlaceholderValue): string => {
  if (value === null || value === undefined) return '';
  if (typeof value === 'number') return Number.isFinite(value) ? String(value) : '';
  return value;
};

const readRawString = (raw: Record<string, unknown>, key: string): string | null => {
  const value = raw[key];
  if (typeof value === 'string') {
    const trimmed = value.trim();
    return trimmed.length > 0 ? trimmed : null;
  }
  if (typeof value === 'number' && Number.isFinite(value)) return String(value);
  return null;
};

const resolveMappedRecord = (draft: ScripterImportDraft): Partial<MappedScripterRecord> =>
  draft.mapped ?? {};

export const buildScrapeTemplateValues = (
  draft: ScripterImportDraft,
  candidate: ProductScrapeCandidate
): ScrapeTemplateValues => {
  const mapped = resolveMappedRecord(draft);
  const externalId =
    draft.externalId ??
    mapped.externalId ??
    readRawString(draft.raw, 'product_id') ??
    readRawString(draft.raw, 'id');
  const brand = mapped.brand ?? readRawString(draft.raw, 'producer');
  const category = mapped.category ?? readRawString(draft.raw, 'category');
  const firstImage = candidate.imageLinks[0] ?? mapped.images?.[0] ?? null;

  return {
    name: candidate.title,
    title: candidate.title,
    description: mapped.description ?? draft.draft.description_en ?? null,
    price: candidate.price,
    sourcePrice: candidate.price,
    currency: mapped.currency ?? readRawString(draft.raw, 'currency'),
    sku: candidate.sku,
    sourceSku: mapped.sku ?? draft.draft.sku ?? null,
    externalId,
    productId: readRawString(draft.raw, 'product_id') ?? externalId,
    brand,
    producer: brand,
    category,
    sourceUrl: candidate.sourceUrl,
    supplierLink: candidate.sourceUrl,
    imageUrl: firstImage,
  };
};

export const renderScrapeTemplateText = (
  value: string | null | undefined,
  values: ScrapeTemplateValues
): string | null => {
  const template = normalizeTemplateString(value);
  if (template === null) return null;
  const rendered = template.replace(PLACEHOLDER_PATTERN, (_match, key: string) =>
    valueToString(values[key])
  );
  const trimmed = rendered.trim();
  return trimmed.length > 0 ? trimmed : null;
};

export const renderScrapeTemplateParameterValues = (
  parameters: ProductDraft['parameters'],
  values: ScrapeTemplateValues
): ProductParameterValue[] =>
  (parameters ?? [])
    .map((parameter): ProductParameterValue | null => {
      const parameterId = normalizeTemplateString(parameter.parameterId);
      if (parameterId === null) return null;
      return {
        parameterId,
        value: renderScrapeTemplateText(String(parameter.value ?? ''), values) ?? '',
      };
    })
    .filter((parameter): parameter is ProductParameterValue => parameter !== null);

export const renderScrapeTemplateCustomFields = (
  customFields: ProductDraft['customFields'],
  values: ScrapeTemplateValues
): ProductCustomFieldValue[] =>
  (customFields ?? [])
    .map((customField): ProductCustomFieldValue | null => {
      const fieldId = normalizeTemplateString(customField.fieldId);
      if (fieldId === null) return null;
      return {
        fieldId,
        ...(customField.textValue !== undefined
          ? { textValue: renderScrapeTemplateText(customField.textValue, values) }
          : {}),
        ...(customField.selectedOptionIds !== undefined
          ? { selectedOptionIds: customField.selectedOptionIds }
          : {}),
      };
    })
    .filter((customField): customField is ProductCustomFieldValue => customField !== null);

export const renderScrapeTemplateMarketplaceOverrides = (
  overrides: ProductDraft['marketplaceContentOverrides'],
  values: ScrapeTemplateValues
): ProductMarketplaceContentOverrideDraft[] =>
  (overrides ?? [])
    .map((override): ProductMarketplaceContentOverrideDraft | null => {
      const integrationIds = override.integrationIds.filter(
        (integrationId) => integrationId.trim().length > 0
      );
      if (integrationIds.length === 0) return null;
      return {
        integrationIds,
        title: renderScrapeTemplateText(override.title, values),
        description: renderScrapeTemplateText(override.description, values),
      };
    })
    .filter(
      (override): override is ProductMarketplaceContentOverrideDraft => override !== null
    );

export const renderScrapeTemplateNotes = (
  notes: ProductDraft['notes'],
  values: ScrapeTemplateValues
): ProductNotes | null => {
  if (notes === null || notes === undefined) return null;
  const text = renderScrapeTemplateText(notes.text, values);
  const color = normalizeTemplateString(notes.color);
  if (text === null && color === null) return null;
  return { text, color };
};

